insert into public.departments (id, slug, name, arabic_name, description, icon, display_order, is_active, prerequisite_module_id, prerequisite_note) values ('hadith-sciences', 'hadith-sciences', 'Hadith Sciences', 'علوم الحديث', 'How the Sunnah was preserved, the six books, and how narrations are graded.', 'scroll', 4, false, NULL, NULL);
insert into public.departments (id, slug, name, arabic_name, description, icon, display_order, is_active, prerequisite_module_id, prerequisite_note) values ('seerah', 'seerah', 'Seerah', 'السيرة النبوية', 'The life of the Prophet ﷺ from Makkah to Madinah — his biography as guidance.', 'palm', 5, false, NULL, NULL);
insert into public.departments (id, slug, name, arabic_name, description, icon, display_order, is_active, prerequisite_module_id, prerequisite_note) values ('tazkiyah', 'tazkiyah', 'Tazkiyat al-Nafs', 'تزكية النفس', 'Purification of the soul upon the Sunnah, beginning with Ibn al-Qayyim''s The Disease and the Cure.', 'heart', 6, false, NULL, NULL);
insert into public.departments (id, slug, name, arabic_name, description, icon, display_order, is_active, prerequisite_module_id, prerequisite_note) values ('arabic-language', 'arabic-language', 'Arabic Language', 'اللغة العربية', 'Quranic Arabic from the alphabet to al-Ajurrumiyyah, with interactive exercises.', 'letters', 7, false, NULL, NULL);
insert into public.departments (id, slug, name, arabic_name, description, icon, display_order, is_active, prerequisite_module_id, prerequisite_note) values ('dawah', 'dawah', 'Dawah', 'الدعوة', 'The methodology and etiquette of calling to Allah with wisdom.', 'minaret', 8, false, NULL, NULL);
insert into public.departments (id, slug, name, arabic_name, description, icon, display_order, is_active, prerequisite_module_id, prerequisite_note) values ('refutations', 'refutations', 'Refutations & Warnings', 'الردود', 'What bid''ah is, and the positions of the historical sects — once the foundations are firm.', 'shield', 9, false, 'usul-al-thalathah', 'Complete the Aqeedah module “Usul al-Thalathah” first — refutations are only understood once the correct position is firm.');
insert into public.departments (id, slug, name, arabic_name, description, icon, display_order, is_active, prerequisite_module_id, prerequisite_note) values ('fatawa-library', 'fatawa-library', 'Q&A / Fatawa Library', 'الفتاوى', 'Selected verdicts of the major scholars, searchable and organized by topic.', 'question', 10, false, NULL, NULL);
insert into public.modules (id, department_id, slug, name, description, display_order, prerequisite_module_id, estimated_minutes) values ('introduction', 'aqeedah', 'introduction', 'Introduction: Preparing to Seek Knowledge', 'Before the first lesson: purifying your intention (ikhlas), knowing that guidance is from Allah and relying upon Him, and the virtue and manners of seeking ilm.', 0, NULL, 150);
insert into public.modules (id, department_id, slug, name, description, display_order, prerequisite_module_id, estimated_minutes) values ('five-pillars', 'aqeedah', 'five-pillars', 'The Five Pillars of Islam', 'What Islam is built upon: the two testimonies, prayer, zakah, fasting and hajj — each established from the Quran and the Sunnah.', 1, 'introduction', 220);
insert into public.modules (id, department_id, slug, name, description, display_order, prerequisite_module_id, estimated_minutes) values ('six-pillars', 'aqeedah', 'six-pillars', 'The Six Pillars of Iman', 'Belief in Allah, His angels, His books, His messengers, the Last Day, and al-qadar — the inward foundation of the religion.', 2, 'five-pillars', 220);
insert into public.modules (id, department_id, slug, name, description, display_order, prerequisite_module_id, estimated_minutes) values ('usul-al-thalathah', 'aqeedah', 'usul-al-thalathah', 'Usul al-Thalathah (The Three Fundamentals)', 'A guided journey through Shaykh Muhammad ibn Abd al-Wahhab''s primer on the three questions every soul will be asked: Who is your Lord? What is your religion? Who is your Prophet ﷺ?', 3, 'six-pillars', 220);
insert into public.modules (id, department_id, slug, name, description, display_order, prerequisite_module_id, estimated_minutes) values ('categories-of-tawheed', 'aqeedah', 'categories-of-tawheed', 'The Categories of Tawheed', 'Tawheed of lordship, of worship, and of Allah''s names and attributes — and the shirk that nullifies each.', 4, 'usul-al-thalathah', 220);
insert into public.modules (id, department_id, slug, name, description, display_order, prerequisite_module_id, estimated_minutes) values ('qawaid-al-arba', 'aqeedah', 'qawaid-al-arba', 'Al-Qawa''id al-Arba'' (The Four Principles)', 'Four short principles that expose the reality of shirk in every era — an introductory breakdown of the famous matn.', 5, 'categories-of-tawheed', 170);
insert into public.modules (id, department_id, slug, name, description, display_order, prerequisite_module_id, estimated_minutes) values ('nawaqid-al-islam', 'aqeedah', 'nawaqid-al-islam', 'Nawaqid al-Islam (The Nullifiers of Islam)', 'The ten matters Shaykh Muhammad ibn Abd al-Wahhab gathered that nullify a person''s Islam — each with its proof, so a Muslim knows what to guard against.', 6, 'qawaid-al-arba', 130);
insert into public.modules (id, department_id, slug, name, description, display_order, prerequisite_module_id, estimated_minutes) values ('usul-al-sittah', 'aqeedah', 'usul-al-sittah', 'Usul al-Sittah (The Six Foundations)', 'Six short, decisive foundations of the religion — clear enough that a child could grasp them, yet missed by many. A guided reading of the famous matn.', 7, 'nawaqid-al-islam', 130);
insert into public.modules (id, department_id, slug, name, description, display_order, prerequisite_module_id, estimated_minutes) values ('kashf-al-shubuhat', 'aqeedah', 'kashf-al-shubuhat', 'Kashf al-Shubuhat (Removal of the Doubts)', 'How to answer the doubts raised against tawheed — the very arguments the mushrikun of old and today rely on, dismantled from the Quran and Sunnah.', 8, 'usul-al-sittah', 170);
insert into public.lessons (id, module_id, slug, title, content_html, display_order, video_youtube_url, video_scholar, video_title, book_recommendations, based_on) values ('introduction--ikhlas', 'introduction', 'ikhlas', 'Ikhlas (Sincerity)', 'بِسْمِ اللَّهِ الرَّحْمَٰنِ الرَّحِيمِ
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('introduction--ikhlas--p1', 'introduction--ikhlas', 'quran', 'وَمَا أُمِرُوا إِلَّا لِيَعْبُدُوا اللَّهَ مُخْلِصِينَ لَهُ الدِّينَ حُنَفَاءَ', 'And they were not commanded except to worship Allah, making the religion sincerely His, inclining to truth.', 'Surah al-Bayyinah 98:5', 1);
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('introduction--ikhlas--p2', 'introduction--ikhlas', 'hadith', 'إِنَّمَا الأَعْمَالُ بِالنِّيَّاتِ، وَإِنَّمَا لِكُلِّ امْرِئٍ مَا نَوَى', 'Actions are only by intentions, and every person shall have only what he intended.', 'Sahih al-Bukhari #1; Sahih Muslim #1907', 2);
insert into public.videos (id, lesson_id, youtube_url, title, scholar, topic) values ('video-introduction--ikhlas', 'introduction--ikhlas', 'https://www.youtube.com/watch?v=FuUWeVpN0Ak', 'Learn How to Purify Your Intention', 'Shaykh Salih al-''Usaymi', 'Ikhlas (Sincerity)');
insert into public.lessons (id, module_id, slug, title, content_html, display_order, video_youtube_url, video_scholar, video_title, book_recommendations, based_on) values ('introduction--guidance', 'introduction', 'guidance-is-from-allah', 'Hidayah (Guidance)', 'A person may gather books and attend classes and still remain unguided, because guidance is in the Hand of Allah alone. Allah the Almighty said to His Prophet ﷺ:
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('introduction--guidance--p1', 'introduction--guidance', 'quran', 'إِنَّكَ لَا تَهْدِي مَنْ أَحْبَبْتَ وَلَٰكِنَّ اللَّهَ يَهْدِي مَن يَشَاءُ ۚ وَهُوَ أَعْلَمُ بِالْمُهْتَدِينَ', 'Indeed, you do not guide whom you love, but Allah guides whom He wills. And He is most knowing of the guided.', 'Surah al-Qasas 28:56', 1);
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('introduction--guidance--p2', 'introduction--guidance', 'quran', 'اهْدِنَا الصِّرَاطَ الْمُسْتَقِيمَ', 'Guide us to the straight path.', 'Surah al-Fatiha 1:6', 2);
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('introduction--guidance--p3', 'introduction--guidance', 'hadith', 'يَا مُقَلِّبَ الْقُلُوبِ ثَبِّتْ قَلْبِي عَلَى دِينِكَ', 'O Turner of the hearts, keep my heart firm upon Your religion.', 'Sunan at-Tirmidhi #2140', 3);
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('introduction--guidance--p4', 'introduction--guidance', 'hadith', 'يَا عِبَادِي كُلُّكُمْ ضَالٌّ إِلَّا مَنْ هَدَيْتُهُ فَاسْتَهْدُونِي أَهْدِكُمْ', 'O My servants, all of you are astray except those whom I guide, so seek guidance from Me and I shall guide you.', 'Sahih Muslim #2577', 4);
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('introduction--guidance--p5', 'introduction--guidance', 'quran', 'وَمَن يَتَوَكَّلْ عَلَى اللَّهِ فَهُوَ حَسْبُهُ ۚ إِنَّ اللَّهَ بَالِغُ أَمْرِهِ', 'And whoever relies upon Allah — He is sufficient for him. Indeed, Allah will accomplish His purpose.', 'Surah at-Talaq 65:3', 5);
insert into public.videos (id, lesson_id, youtube_url, title, scholar, topic) values ('video-introduction--guidance', 'introduction--guidance', 'https://www.youtube.com/watch?v=UBbkbLezDhg', 'The Correct Understanding of Tawakkul upon Allah', 'Shaykh Muhammad ibn Salih al-Uthaymeen', 'Hidayah (Guidance)');
insert into public.lessons (id, module_id, slug, title, content_html, display_order, video_youtube_url, video_scholar, video_title, book_recommendations, based_on) values ('introduction--seeking-ilm', 'introduction', 'seeking-ilm', 'Talab al-Ilm (Seeking Knowledge)', 'Seeking knowledge of the religion is among the greatest acts of worship, and learning what the worship of Allah requires is an obligation upon every Muslim. Abu Hurairah (may Allah be pleased with him) narrated that the Messenger of Allah ﷺ said:
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('introduction--seeking-ilm--p1', 'introduction--seeking-ilm', 'hadith', 'مَنْ سَلَكَ طَرِيقًا يَلْتَمِسُ فِيهِ عِلْمًا سَهَّلَ اللَّهُ لَهُ بِهِ طَرِيقًا إِلَى الْجَنَّةِ', 'Whoever treads a path seeking knowledge in it, Allah makes easy for him thereby a path to Paradise.', 'Sahih Muslim #2699', 1);
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('introduction--seeking-ilm--p2', 'introduction--seeking-ilm', 'quran', 'يَرْفَعِ اللَّهُ الَّذِينَ آمَنُوا مِنكُمْ وَالَّذِينَ أُوتُوا الْعِلْمَ دَرَجَاتٍ', 'Allah will raise those who have believed among you and those who were given knowledge by degrees.', 'Surah al-Mujadilah 58:11', 2);
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('introduction--seeking-ilm--p3', 'introduction--seeking-ilm', 'quran', 'وَقُل رَّبِّ زِدْنِي عِلْمًا', 'And say: My Lord, increase me in knowledge.', 'Surah Ta-Ha 20:114', 3);
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('introduction--seeking-ilm--p4', 'introduction--seeking-ilm', 'hadith', 'مَنْ يُرِدِ اللَّهُ بِهِ خَيْرًا يُفَقِّهْهُ فِي الدِّينِ', 'Whoever Allah wants good for, He gives him understanding of the religion.', 'Sahih al-Bukhari #71', 4);
insert into public.videos (id, lesson_id, youtube_url, title, scholar, topic) values ('video-introduction--seeking-ilm', 'introduction--seeking-ilm', 'https://www.youtube.com/watch?v=QSlxiXbM9hs', 'Comprehensive Words on How to Seek Knowledge', 'Shaykh Abdul-Aziz ibn Baz', 'Talab al-Ilm (Seeking Knowledge)');
insert into public.lessons (id, module_id, slug, title, content_html, display_order, video_youtube_url, video_scholar, video_title, book_recommendations, based_on) values ('five-pillars--hadith-of-jibreel', 'five-pillars', 'hadith-of-jibreel', 'The Hadith of Jibreel: What Islam Is Built Upon', '**Islam** is a defined religion with pillars, and Allah''s Messenger ﷺ named them himself. The angel **Jibreel** came to the Prophet ﷺ in the form of a man and questioned him in front of his Companions: What is Islam? What is iman? What is ihsan? The Prophet ﷺ then said, “That was Jibreel; he came to teach you your religion.” This module explains the first of those answers.
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('five-pillars--hadith-of-jibreel--p1', 'five-pillars--hadith-of-jibreel', 'hadith', 'الإِسْلاَمُ أَنْ تَشْهَدَ أَنْ لاَ إِلَهَ إِلاَّ اللَّهُ وَأَنَّ مُحَمَّدًا رَسُولُ اللَّهِ، وَتُقِيمَ الصَّلاَةَ، وَتُؤْتِيَ الزَّكَاةَ، وَتَصُومَ رَمَضَانَ، وَتَحُجَّ الْبَيْتَ إِنِ اسْتَطَعْتَ إِلَيْهِ سَبِيلاً', 'Islam is that you testify that none has the right to be worshipped except Allah and that Muhammad is the Messenger of Allah, that you establish the prayer, give the zakah, fast Ramadan, and perform hajj to the House if you are able to find a way to it.', 'Sahih Muslim #8 (the hadith of Jibreel)', 1);
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('five-pillars--hadith-of-jibreel--p2', 'five-pillars--hadith-of-jibreel', 'hadith', 'بُنِيَ الإِسْلاَمُ عَلَى خَمْسٍ: شَهَادَةِ أَنْ لاَ إِلَهَ إِلاَّ اللَّهُ وَأَنَّ مُحَمَّدًا رَسُولُ اللَّهِ، وَإِقَامِ الصَّلاَةِ، وَإِيتَاءِ الزَّكَاةِ، وَالْحَجِّ، وَصَوْمِ رَمَضَانَ', 'Islam is built upon five: the testimony that none has the right to be worshipped except Allah and that Muhammad is the Messenger of Allah, establishing the prayer, giving the zakah, hajj, and fasting Ramadan.', 'Sahih al-Bukhari #8; Sahih Muslim #16', 2);
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('five-pillars--hadith-of-jibreel--p3', 'five-pillars--hadith-of-jibreel', 'quran', 'إِنَّ الدِّينَ عِندَ اللَّهِ الْإِسْلَامُ', 'Indeed, the religion in the sight of Allah is Islam.', 'Surah Aal Imran 3:19', 3);
insert into public.videos (id, lesson_id, youtube_url, title, scholar, topic) values ('video-five-pillars--hadith-of-jibreel', 'five-pillars--hadith-of-jibreel', 'https://www.youtube.com/watch?v=cDSfVWEB49Q', 'The Pillars of Islam and Iman', 'Shaykh Muhammad ibn Salih al-Uthaymeen', 'The Hadith of Jibreel: What Islam Is Built Upon');
insert into public.lessons (id, module_id, slug, title, content_html, display_order, video_youtube_url, video_scholar, video_title, book_recommendations, based_on) values ('five-pillars--the-shahadatayn', 'five-pillars', 'the-shahadatayn', 'The Shahadatayn: The Two Testimonies', 'The first pillar is the statement **La ilaha illa Allah**: *none has the right to be worshipped except Allah*. It contains a negation and an affirmation. It negates the right of worship from everything besides Allah, whether an idol, a saint, a prophet, a star, or a desire, and it affirms worship for Allah alone. The scholars call this the word of **tawheed**, and it is what every messenger was sent with.
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('five-pillars--the-shahadatayn--p1', 'five-pillars--the-shahadatayn', 'quran', 'وَلَقَدْ بَعَثْنَا فِي كُلِّ أُمَّةٍ رَّسُولًا أَنِ اعْبُدُوا اللَّهَ وَاجْتَنِبُوا الطَّاغُوتَ', 'And We certainly sent into every nation a messenger, [saying]: worship Allah and avoid taghut (false objects of worship).', 'Surah an-Nahl 16:36', 1);
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('five-pillars--the-shahadatayn--p2', 'five-pillars--the-shahadatayn', 'quran', 'فَاعْلَمْ أَنَّهُ لَا إِلَٰهَ إِلَّا اللَّهُ وَاسْتَغْفِرْ لِذَنبِكَ', 'So know that none has the right to be worshipped except Allah, and seek forgiveness for your sin.', 'Surah Muhammad 47:19', 2);
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('five-pillars--the-shahadatayn--p3', 'five-pillars--the-shahadatayn', 'hadith', 'إِنَّكَ تَقْدَمُ عَلَى قَوْمٍ مِنْ أَهْلِ الْكِتَابِ، فَلْيَكُنْ أَوَّلَ مَا تَدْعُوهُمْ إِلَيْهِ شَهَادَةُ أَنْ لاَ إِلَهَ إِلاَّ اللَّهُ', 'You are going to a people of the Book, so let the first thing you call them to be the testimony that none has the right to be worshipped except Allah.', 'Sahih al-Bukhari #1496; Sahih Muslim #19', 3);
insert into public.videos (id, lesson_id, youtube_url, title, scholar, topic) values ('video-five-pillars--the-shahadatayn', 'five-pillars--the-shahadatayn', 'https://www.youtube.com/watch?v=cDSfVWEB49Q', 'The Pillars of Islam and Iman', 'Shaykh Muhammad ibn Salih al-Uthaymeen', 'The Shahadatayn: The Two Testimonies');
insert into public.lessons (id, module_id, slug, title, content_html, display_order, video_youtube_url, video_scholar, video_title, book_recommendations, based_on) values ('five-pillars--salah-and-zakah', 'five-pillars', 'salah-and-zakah', 'Salah and Zakah: The Rights of Allah and the Rights of Wealth', 'After the testimony, the greatest pillar is the **salah**, the five daily prayers. Throughout the Quran, Allah pairs the command to establish prayer with the command to give zakah, because the first is the right of Allah upon the body and the second is His right upon wealth:
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('five-pillars--salah-and-zakah--p1', 'five-pillars--salah-and-zakah', 'quran', 'وَأَقِيمُوا الصَّلَاةَ وَآتُوا الزَّكَاةَ وَارْكَعُوا مَعَ الرَّاكِعِينَ', 'And establish the prayer, and give the zakah, and bow with those who bow.', 'Surah al-Baqarah 2:43', 1);
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('five-pillars--salah-and-zakah--p2', 'five-pillars--salah-and-zakah', 'hadith', 'بَيْنَ الرَّجُلِ وَبَيْنَ الشِّرْكِ وَالْكُفْرِ تَرْكُ الصَّلاَةِ', 'Between a man and shirk and disbelief stands the abandonment of the prayer.', 'Sahih Muslim #82', 2);
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('five-pillars--salah-and-zakah--p3', 'five-pillars--salah-and-zakah', 'quran', 'خُذْ مِنْ أَمْوَالِهِمْ صَدَقَةً تُطَهِّرُهُمْ وَتُزَكِّيهِم بِهَا', 'Take from their wealth a charity by which you purify them and cause them to increase.', 'Surah at-Tawbah 9:103', 3);
insert into public.videos (id, lesson_id, youtube_url, title, scholar, topic) values ('video-five-pillars--salah-and-zakah', 'five-pillars--salah-and-zakah', 'https://www.youtube.com/watch?v=cDSfVWEB49Q', 'The Pillars of Islam and Iman', 'Shaykh Muhammad ibn Salih al-Uthaymeen', 'Salah and Zakah: The Rights of Allah and the Rights of Wealth');
insert into public.lessons (id, module_id, slug, title, content_html, display_order, video_youtube_url, video_scholar, video_title, book_recommendations, based_on) values ('five-pillars--sawm-and-hajj', 'five-pillars', 'sawm-and-hajj', 'Sawm and Hajj: The Fast of Ramadan and the Pilgrimage', 'The fourth pillar is fasting **Ramadan**: abstaining from food, drink and marital relations from true dawn until sunset, as worship of Allah. Its obligation is stated in the Quran, along with its purpose: **taqwa**, the fearful mindfulness of Allah:
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('five-pillars--sawm-and-hajj--p1', 'five-pillars--sawm-and-hajj', 'quran', 'يَا أَيُّهَا الَّذِينَ آمَنُوا كُتِبَ عَلَيْكُمُ الصِّيَامُ كَمَا كُتِبَ عَلَى الَّذِينَ مِن قَبْلِكُمْ لَعَلَّكُمْ تَتَّقُونَ', 'O you who believe, fasting has been prescribed upon you as it was prescribed upon those before you, that you may attain taqwa.', 'Surah al-Baqarah 2:183', 1);
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('five-pillars--sawm-and-hajj--p2', 'five-pillars--sawm-and-hajj', 'quran', 'وَلِلَّهِ عَلَى النَّاسِ حِجُّ الْبَيْتِ مَنِ اسْتَطَاعَ إِلَيْهِ سَبِيلًا', 'And due to Allah from the people is pilgrimage to the House — for whoever is able to find a way to it.', 'Surah Aal Imran 3:97', 2);
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('five-pillars--sawm-and-hajj--p3', 'five-pillars--sawm-and-hajj', 'hadith', 'مَنْ حَجَّ لِلَّهِ فَلَمْ يَرْفُثْ وَلَمْ يَفْسُقْ رَجَعَ كَيَوْمِ وَلَدَتْهُ أُمُّهُ', 'Whoever performs hajj for Allah and does not commit obscenity or transgression returns [free of sin] as on the day his mother bore him.', 'Sahih al-Bukhari #1521', 3);
insert into public.videos (id, lesson_id, youtube_url, title, scholar, topic) values ('video-five-pillars--sawm-and-hajj', 'five-pillars--sawm-and-hajj', 'https://www.youtube.com/watch?v=cDSfVWEB49Q', 'The Pillars of Islam and Iman', 'Shaykh Muhammad ibn Salih al-Uthaymeen', 'Sawm and Hajj: The Fast of Ramadan and the Pilgrimage');
insert into public.lessons (id, module_id, slug, title, content_html, display_order, video_youtube_url, video_scholar, video_title, book_recommendations, based_on) values ('six-pillars--what-is-iman', 'six-pillars', 'what-is-iman', 'What Is Iman? Definition and the Six Pillars', 'If Islam describes the outward submission of the limbs, **iman** describes what the heart believes, says and does. When Jibreel asked the Prophet ﷺ, “What is iman?”, he answered with six matters. These are the pillars of iman:
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('six-pillars--what-is-iman--p1', 'six-pillars--what-is-iman', 'hadith', 'أَنْ تُؤْمِنَ بِاللَّهِ وَمَلاَئِكَتِهِ وَكُتُبِهِ وَرُسُلِهِ وَالْيَوْمِ الآخِرِ وَتُؤْمِنَ بِالْقَدَرِ خَيْرِهِ وَشَرِّهِ', '[Iman is] that you believe in Allah, His angels, His books, His messengers, and the Last Day, and that you believe in the decree — its good and its bad.', 'Sahih Muslim #8 (the hadith of Jibreel)', 1);
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('six-pillars--what-is-iman--p2', 'six-pillars--what-is-iman', 'quran', 'وَلَٰكِنَّ الْبِرَّ مَنْ آمَنَ بِاللَّهِ وَالْيَوْمِ الْآخِرِ وَالْمَلَائِكَةِ وَالْكِتَابِ وَالنَّبِيِّينَ', 'But righteousness is [in] the one who believes in Allah, the Last Day, the angels, the Book, and the prophets.', 'Surah al-Baqarah 2:177', 2);
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('six-pillars--what-is-iman--p3', 'six-pillars--what-is-iman', 'hadith', 'الإِيمَانُ بِضْعٌ وَسَبْعُونَ شُعْبَةً، فَأَفْضَلُهَا قَوْلُ لاَ إِلَهَ إِلاَّ اللَّهُ، وَأَدْنَاهَا إِمَاطَةُ الأَذَى عَنِ الطَّرِيقِ، وَالْحَيَاءُ شُعْبَةٌ مِنَ الإِيمَانِ', 'Iman is seventy-odd branches: the highest of them is the statement ''none has the right to be worshipped except Allah'', the lowest is removing something harmful from the road, and modesty is a branch of iman.', 'Sahih Muslim #35', 3);
insert into public.videos (id, lesson_id, youtube_url, title, scholar, topic) values ('video-six-pillars--what-is-iman', 'six-pillars--what-is-iman', 'https://www.youtube.com/watch?v=cDSfVWEB49Q', 'The Pillars of Islam and Iman', 'Shaykh Muhammad ibn Salih al-Uthaymeen', 'What Is Iman? Definition and the Six Pillars');
insert into public.lessons (id, module_id, slug, title, content_html, display_order, video_youtube_url, video_scholar, video_title, book_recommendations, based_on) values ('six-pillars--allah-and-the-angels', 'six-pillars', 'allah-and-the-angels', 'Belief in Allah and Belief in the Angels', '**Belief in Allah** contains four things, as the scholars explain: belief in His existence; belief in His **rububiyyah** (He alone creates, owns and governs); belief in His **uluhiyyah** (He alone deserves worship); and belief in His **names and attributes** as He and His Messenger ﷺ described them. Each of these will be studied in a later module; here we learn the outline. One ayah gathers the whole command:
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('six-pillars--allah-and-the-angels--p1', 'six-pillars--allah-and-the-angels', 'quran', 'يَا أَيُّهَا الَّذِينَ آمَنُوا آمِنُوا بِاللَّهِ وَرَسُولِهِ وَالْكِتَابِ الَّذِي نَزَّلَ عَلَىٰ رَسُولِهِ وَالْكِتَابِ الَّذِي أَنزَلَ مِن قَبْلُ ۚ وَمَن يَكْفُرْ بِاللَّهِ وَمَلَائِكَتِهِ وَكُتُبِهِ وَرُسُلِهِ وَالْيَوْمِ الْآخِرِ فَقَدْ ضَلَّ ضَلَالًا بَعِيدًا', 'O you who believe, believe in Allah and His Messenger and the Book He sent down upon His Messenger and the Book He sent down before. And whoever disbelieves in Allah, His angels, His books, His messengers, and the Last Day has certainly gone far astray.', 'Surah an-Nisa 4:136', 1);
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('six-pillars--allah-and-the-angels--p2', 'six-pillars--allah-and-the-angels', 'quran', 'لَّا يَعْصُونَ اللَّهَ مَا أَمَرَهُمْ وَيَفْعَلُونَ مَا يُؤْمَرُونَ', 'They do not disobey Allah in what He commands them, and they do what they are commanded.', 'Surah at-Tahrim 66:6', 2);
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('six-pillars--allah-and-the-angels--p3', 'six-pillars--allah-and-the-angels', 'hadith', 'خُلِقَتِ الْمَلاَئِكَةُ مِنْ نُورٍ، وَخُلِقَ الْجَانُّ مِنْ مَارِجٍ مِنْ نَارٍ، وَخُلِقَ آدَمُ مِمَّا وُصِفَ لَكُمْ', 'The angels were created from light, the jinn were created from a smokeless flame of fire, and Adam was created from that which has been described to you.', 'Sahih Muslim #2996', 3);
insert into public.videos (id, lesson_id, youtube_url, title, scholar, topic) values ('video-six-pillars--allah-and-the-angels', 'six-pillars--allah-and-the-angels', 'https://www.youtube.com/watch?v=cDSfVWEB49Q', 'The Pillars of Islam and Iman', 'Shaykh Muhammad ibn Salih al-Uthaymeen', 'Belief in Allah and Belief in the Angels');
insert into public.lessons (id, module_id, slug, title, content_html, display_order, video_youtube_url, video_scholar, video_title, book_recommendations, based_on) values ('six-pillars--books-and-messengers', 'six-pillars', 'books-and-messengers', 'Belief in the Books and the Messengers', 'Allah did not leave His creation without guidance. He sent **messengers** to every nation and sent down **books** with them, so that no one may stand before Him on the Day of Judgment with an excuse:
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('six-pillars--books-and-messengers--p1', 'six-pillars--books-and-messengers', 'quran', 'لَقَدْ أَرْسَلْنَا رُسُلَنَا بِالْبَيِّنَاتِ وَأَنزَلْنَا مَعَهُمُ الْكِتَابَ وَالْمِيزَانَ لِيَقُومَ النَّاسُ بِالْقِسْطِ', 'We have certainly sent Our messengers with clear proofs, and We sent down with them the Book and the balance so that the people may uphold justice.', 'Surah al-Hadid 57:25', 1);
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('six-pillars--books-and-messengers--p2', 'six-pillars--books-and-messengers', 'quran', 'وَمَا أَرْسَلْنَا مِن قَبْلِكَ مِن رَّسُولٍ إِلَّا نُوحِي إِلَيْهِ أَنَّهُ لَا إِلَٰهَ إِلَّا أَنَا فَاعْبُدُونِ', 'And We did not send any messenger before you except that We revealed to him: none has the right to be worshipped except Me, so worship Me.', 'Surah al-Anbiya 21:25', 2);
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('six-pillars--books-and-messengers--p3', 'six-pillars--books-and-messengers', 'quran', 'مَّا كَانَ مُحَمَّدٌ أَبَا أَحَدٍ مِّن رِّجَالِكُمْ وَلَٰكِن رَّسُولَ اللَّهِ وَخَاتَمَ النَّبِيِّينَ', 'Muhammad is not the father of any of your men, but the Messenger of Allah and the seal of the prophets.', 'Surah al-Ahzab 33:40', 3);
insert into public.videos (id, lesson_id, youtube_url, title, scholar, topic) values ('video-six-pillars--books-and-messengers', 'six-pillars--books-and-messengers', 'https://www.youtube.com/watch?v=cDSfVWEB49Q', 'The Pillars of Islam and Iman', 'Shaykh Muhammad ibn Salih al-Uthaymeen', 'Belief in the Books and the Messengers');
insert into public.lessons (id, module_id, slug, title, content_html, display_order, video_youtube_url, video_scholar, video_title, book_recommendations, based_on) values ('six-pillars--last-day-and-qadar', 'six-pillars', 'last-day-and-qadar', 'The Last Day and al-Qadar: The Decree', '**Belief in the Last Day** means certainty in everything the revelation reports after death: the trial of the grave and its bliss or punishment, the Resurrection, the gathering, the records handed to the right or the left, the scale, the sirat, the intercession, and finally Paradise or the Fire, forever. The reckoning covers even an atom''s weight:
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('six-pillars--last-day-and-qadar--p1', 'six-pillars--last-day-and-qadar', 'quran', 'فَمَن يَعْمَلْ مِثْقَالَ ذَرَّةٍ خَيْرًا يَرَهُ ۝ وَمَن يَعْمَلْ مِثْقَالَ ذَرَّةٍ شَرًّا يَرَهُ', 'So whoever does an atom''s weight of good will see it, and whoever does an atom''s weight of evil will see it.', 'Surah az-Zalzalah 99:7-8', 1);
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('six-pillars--last-day-and-qadar--p2', 'six-pillars--last-day-and-qadar', 'quran', 'إِنَّا كُلَّ شَيْءٍ خَلَقْنَاهُ بِقَدَرٍ', 'Indeed, all things We created with a decree.', 'Surah al-Qamar 54:49', 2);
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('six-pillars--last-day-and-qadar--p3', 'six-pillars--last-day-and-qadar', 'hadith', 'كَتَبَ اللَّهُ مَقَادِيرَ الْخَلاَئِقِ قَبْلَ أَنْ يَخْلُقَ السَّمَوَاتِ وَالأَرْضَ بِخَمْسِينَ أَلْفَ سَنَةٍ', 'Allah wrote the decrees of the creation fifty thousand years before He created the heavens and the earth.', 'Sahih Muslim #2653', 3);
insert into public.videos (id, lesson_id, youtube_url, title, scholar, topic) values ('video-six-pillars--last-day-and-qadar', 'six-pillars--last-day-and-qadar', 'https://www.youtube.com/watch?v=cDSfVWEB49Q', 'The Pillars of Islam and Iman', 'Shaykh Muhammad ibn Salih al-Uthaymeen', 'The Last Day and al-Qadar: The Decree');
insert into public.lessons (id, module_id, slug, title, content_html, display_order, video_youtube_url, video_scholar, video_title, book_recommendations, based_on) values ('usul-al-thalathah--four-matters', 'usul-al-thalathah', 'four-matters', 'Introduction: The Four Matters and the Three Questions', '**Thalathat al-Usul** (The Three Fundamental Principles) is a short primer written by Shaykh Muhammad ibn Abd al-Wahhab so that every Muslim, young or old, would know the answers to the three questions of the grave: *Who is your Lord? What is your religion? Who is your prophet?* Generations of students across the world begin their study of aqeedah with this text, and so do we.
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('usul-al-thalathah--four-matters--p1', 'usul-al-thalathah--four-matters', 'quran', 'وَالْعَصْرِ ۝ إِنَّ الْإِنسَانَ لَفِي خُسْرٍ ۝ إِلَّا الَّذِينَ آمَنُوا وَعَمِلُوا الصَّالِحَاتِ وَتَوَاصَوْا بِالْحَقِّ وَتَوَاصَوْا بِالصَّبْرِ', 'By time. Indeed, mankind is in loss — except those who believe, do righteous deeds, counsel one another with the truth, and counsel one another with patience.', 'Surah al-''Asr 103:1-3', 1);
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('usul-al-thalathah--four-matters--p2', 'usul-al-thalathah--four-matters', 'quran', 'فَاعْلَمْ أَنَّهُ لَا إِلَٰهَ إِلَّا اللَّهُ وَاسْتَغْفِرْ لِذَنبِكَ وَلِلْمُؤْمِنِينَ وَالْمُؤْمِنَاتِ', 'So know that none has the right to be worshipped except Allah, and seek forgiveness for your sin and for the believing men and believing women.', 'Surah Muhammad 47:19', 2);
insert into public.videos (id, lesson_id, youtube_url, title, scholar, topic) values ('video-usul-al-thalathah--four-matters', 'usul-al-thalathah--four-matters', 'https://www.youtube.com/watch?v=wt15FdZZ9GY', 'Thalathah Al-Usul — Full Explanation', 'Shaykh Haytham Sarhan', 'Introduction: The Four Matters and the Three Questions');
insert into public.lessons (id, module_id, slug, title, content_html, display_order, video_youtube_url, video_scholar, video_title, book_recommendations, based_on) values ('usul-al-thalathah--who-is-your-lord', 'usul-al-thalathah', 'who-is-your-lord', 'The First Principle: Who Is Your Lord?', 'The author writes: *If it is said to you, “Who is your Lord?”, then say: My Lord is **Allah**, who has nurtured me and nurtured all the worlds with His blessings. He is my object of worship; I have no object of worship besides Him.* The word **Rabb** (Lord) carries all of this: the Creator, the Owner, the Provider, the One who manages every affair of every creature.
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('usul-al-thalathah--who-is-your-lord--p1', 'usul-al-thalathah--who-is-your-lord', 'quran', 'الْحَمْدُ لِلَّهِ رَبِّ الْعَالَمِينَ', 'All praise is due to Allah, Lord of the worlds.', 'Surah al-Fatiha 1:2', 1);
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('usul-al-thalathah--who-is-your-lord--p2', 'usul-al-thalathah--who-is-your-lord', 'quran', 'وَمِنْ آيَاتِهِ اللَّيْلُ وَالنَّهَارُ وَالشَّمْسُ وَالْقَمَرُ ۚ لَا تَسْجُدُوا لِلشَّمْسِ وَلَا لِلْقَمَرِ وَاسْجُدُوا لِلَّهِ الَّذِي خَلَقَهُنَّ إِن كُنتُمْ إِيَّاهُ تَعْبُدُونَ', 'And among His signs are the night and the day and the sun and the moon. Do not prostrate to the sun or to the moon, but prostrate to Allah who created them, if it is Him you worship.', 'Surah Fussilat 41:37', 2);
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('usul-al-thalathah--who-is-your-lord--p3', 'usul-al-thalathah--who-is-your-lord', 'quran', 'يَا أَيُّهَا النَّاسُ اعْبُدُوا رَبَّكُمُ الَّذِي خَلَقَكُمْ وَالَّذِينَ مِن قَبْلِكُمْ لَعَلَّكُمْ تَتَّقُونَ', 'O mankind, worship your Lord who created you and those before you, that you may attain taqwa.', 'Surah al-Baqarah 2:21', 3);
insert into public.videos (id, lesson_id, youtube_url, title, scholar, topic) values ('video-usul-al-thalathah--who-is-your-lord', 'usul-al-thalathah--who-is-your-lord', 'https://www.youtube.com/watch?v=wt15FdZZ9GY', 'Thalathah Al-Usul — Full Explanation', 'Shaykh Haytham Sarhan', 'The First Principle: Who Is Your Lord?');
insert into public.lessons (id, module_id, slug, title, content_html, display_order, video_youtube_url, video_scholar, video_title, book_recommendations, based_on) values ('usul-al-thalathah--what-is-your-religion', 'usul-al-thalathah', 'what-is-your-religion', 'The Second Principle: What Is Your Religion?', 'The author writes: *The religion of Islam is: **submitting to Allah with tawheed, yielding to Him with obedience, and freeing oneself from shirk and its people.*** Memorize this three-part definition. Submission alone is not enough; it must be submission built on tawheed, expressed in obedience, and completed by freeing oneself from shirk and its people.
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('usul-al-thalathah--what-is-your-religion--p1', 'usul-al-thalathah--what-is-your-religion', 'quran', 'وَمَن يَبْتَغِ غَيْرَ الْإِسْلَامِ دِينًا فَلَن يُقْبَلَ مِنْهُ وَهُوَ فِي الْآخِرَةِ مِنَ الْخَاسِرِينَ', 'And whoever seeks a religion other than Islam, it will never be accepted from him, and in the Hereafter he will be among the losers.', 'Surah Aal Imran 3:85', 1);
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('usul-al-thalathah--what-is-your-religion--p2', 'usul-al-thalathah--what-is-your-religion', 'hadith', 'أَنْ تَعْبُدَ اللَّهَ كَأَنَّكَ تَرَاهُ، فَإِنْ لَمْ تَكُنْ تَرَاهُ فَإِنَّهُ يَرَاكَ', '[Ihsan is] that you worship Allah as though you see Him; and if you do not see Him, then indeed He sees you.', 'Sahih Muslim #8 (the hadith of Jibreel)', 2);
insert into public.videos (id, lesson_id, youtube_url, title, scholar, topic) values ('video-usul-al-thalathah--what-is-your-religion', 'usul-al-thalathah--what-is-your-religion', 'https://www.youtube.com/watch?v=wt15FdZZ9GY', 'Thalathah Al-Usul — Full Explanation', 'Shaykh Haytham Sarhan', 'The Second Principle: What Is Your Religion?');
insert into public.lessons (id, module_id, slug, title, content_html, display_order, video_youtube_url, video_scholar, video_title, book_recommendations, based_on) values ('usul-al-thalathah--who-is-your-prophet', 'usul-al-thalathah', 'who-is-your-prophet', 'The Third Principle: Who Is Your Prophet ﷺ?', 'The third principle is knowing your Prophet: **Muhammad ibn Abdillah ibn Abd al-Muttalib ibn Hashim**, of Quraysh, of the Arabs, of the descendants of Isma''il son of Ibrahim ﷺ. He lived sixty-three years: forty before prophethood, and twenty-three as a prophet and messenger. He was raised an orphan in Makkah, known among his people, before any revelation, as **al-Amin**, the trustworthy.
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('usul-al-thalathah--who-is-your-prophet--p1', 'usul-al-thalathah--who-is-your-prophet', 'quran', 'يَا أَيُّهَا الْمُدَّثِّرُ ۝ قُمْ فَأَنذِرْ ۝ وَرَبَّكَ فَكَبِّرْ ۝ وَثِيَابَكَ فَطَهِّرْ ۝ وَالرُّجْزَ فَاهْجُرْ', 'O you wrapped in a cloak: arise and warn, and magnify your Lord, and purify your garments, and shun the idols.', 'Surah al-Muddaththir 74:1-5', 1);
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('usul-al-thalathah--who-is-your-prophet--p2', 'usul-al-thalathah--who-is-your-prophet', 'quran', 'وَمَا أَرْسَلْنَاكَ إِلَّا كَافَّةً لِّلنَّاسِ بَشِيرًا وَنَذِيرًا', 'And We have not sent you except to all of mankind, as a bringer of good tidings and a warner.', 'Surah Saba 34:28', 2);
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('usul-al-thalathah--who-is-your-prophet--p3', 'usul-al-thalathah--who-is-your-prophet', 'quran', 'مَّن يُطِعِ الرَّسُولَ فَقَدْ أَطَاعَ اللَّهَ', 'Whoever obeys the Messenger has obeyed Allah.', 'Surah an-Nisa 4:80', 3);
insert into public.videos (id, lesson_id, youtube_url, title, scholar, topic) values ('video-usul-al-thalathah--who-is-your-prophet', 'usul-al-thalathah--who-is-your-prophet', 'https://www.youtube.com/watch?v=wt15FdZZ9GY', 'Thalathah Al-Usul — Full Explanation', 'Shaykh Haytham Sarhan', 'The Third Principle: Who Is Your Prophet ﷺ?');
insert into public.lessons (id, module_id, slug, title, content_html, display_order, video_youtube_url, video_scholar, video_title, book_recommendations, based_on) values ('categories-of-tawheed--rububiyyah', 'categories-of-tawheed', 'rububiyyah', 'Tawheed ar-Rububiyyah: Oneness of Lordship', '**Tawheed ar-Rububiyyah** is singling out Allah in His actions: He alone creates, He alone provides, He alone gives life and death, and He alone manages the affairs of the heavens and the earth. No atom moves except by His permission.
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('categories-of-tawheed--rububiyyah--p1', 'categories-of-tawheed--rububiyyah', 'quran', 'اللَّهُ خَالِقُ كُلِّ شَيْءٍ ۖ وَهُوَ عَلَىٰ كُلِّ شَيْءٍ وَكِيلٌ', 'Allah is the Creator of all things, and He is, over all things, Disposer of affairs.', 'Surah az-Zumar 39:62', 1);
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('categories-of-tawheed--rububiyyah--p2', 'categories-of-tawheed--rububiyyah', 'quran', 'وَلَئِن سَأَلْتَهُم مَّنْ خَلَقَهُمْ لَيَقُولُنَّ اللَّهُ ۖ فَأَنَّىٰ يُؤْفَكُونَ', 'And if you asked them who created them, they would surely say, ''Allah.'' So how are they deluded away [from the truth]?', 'Surah az-Zukhruf 43:87', 2);
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('categories-of-tawheed--rububiyyah--p3', 'categories-of-tawheed--rububiyyah', 'quran', 'أَفَمَن يَخْلُقُ كَمَن لَّا يَخْلُقُ ۗ أَفَلَا تَذَكَّرُونَ', 'Is He who creates like one who does not create? Will you not then be reminded?', 'Surah an-Nahl 16:17', 3);
insert into public.videos (id, lesson_id, youtube_url, title, scholar, topic) values ('video-categories-of-tawheed--rububiyyah', 'categories-of-tawheed--rububiyyah', 'https://www.youtube.com/watch?v=8mL4qaGY5yQ', '3 Types of Tawheed in Detail', 'Shaykh Salih al-Fawzan', 'Tawheed ar-Rububiyyah: Oneness of Lordship');
insert into public.lessons (id, module_id, slug, title, content_html, display_order, video_youtube_url, video_scholar, video_title, book_recommendations, based_on) values ('categories-of-tawheed--uluhiyyah', 'categories-of-tawheed', 'uluhiyyah', 'Tawheed al-Uluhiyyah: Oneness of Worship', '**Tawheed al-Uluhiyyah**, also called tawheed al-''ibadah, is singling out Allah with the actions of the servants: du''a (supplication), fear, hope, reliance, sacrifice, vows, prostration, and every act of worship, inward or outward. This is the tawheed contained in *La ilaha illa Allah*, the tawheed the messengers were sent for, and the tawheed over which mankind divided.
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('categories-of-tawheed--uluhiyyah--p1', 'categories-of-tawheed--uluhiyyah', 'quran', 'وَمَا خَلَقْتُ الْجِنَّ وَالْإِنسَ إِلَّا لِيَعْبُدُونِ', 'And I did not create the jinn and mankind except to worship Me.', 'Surah adh-Dhariyat 51:56', 1);
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('categories-of-tawheed--uluhiyyah--p2', 'categories-of-tawheed--uluhiyyah', 'hadith', 'حَقُّ اللَّهِ عَلَى الْعِبَادِ أَنْ يَعْبُدُوهُ وَلاَ يُشْرِكُوا بِهِ شَيْئًا', 'The right of Allah upon the servants is that they worship Him and do not associate anything with Him.', 'Sahih al-Bukhari #2856; Sahih Muslim #30', 2);
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('categories-of-tawheed--uluhiyyah--p3', 'categories-of-tawheed--uluhiyyah', 'quran', 'إِيَّاكَ نَعْبُدُ وَإِيَّاكَ نَسْتَعِينُ', 'You alone we worship, and You alone we ask for help.', 'Surah al-Fatiha 1:5', 3);
insert into public.videos (id, lesson_id, youtube_url, title, scholar, topic) values ('video-categories-of-tawheed--uluhiyyah', 'categories-of-tawheed--uluhiyyah', 'https://www.youtube.com/watch?v=8mL4qaGY5yQ', '3 Types of Tawheed in Detail', 'Shaykh Salih al-Fawzan', 'Tawheed al-Uluhiyyah: Oneness of Worship');
insert into public.lessons (id, module_id, slug, title, content_html, display_order, video_youtube_url, video_scholar, video_title, book_recommendations, based_on) values ('categories-of-tawheed--asma-wa-sifat', 'categories-of-tawheed', 'asma-wa-sifat', 'Tawheed al-Asma wa''s-Sifat: Names and Attributes', '**Tawheed al-Asma wa''s-Sifat** is believing in every name Allah named Himself with and every attribute He described Himself with, in His Book or on the tongue of His Messenger ﷺ, affirming them as they came, in the manner that befits His majesty. Allah commanded us to call on Him by them:
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('categories-of-tawheed--asma-wa-sifat--p1', 'categories-of-tawheed--asma-wa-sifat', 'quran', 'وَلِلَّهِ الْأَسْمَاءُ الْحُسْنَىٰ فَادْعُوهُ بِهَا ۖ وَذَرُوا الَّذِينَ يُلْحِدُونَ فِي أَسْمَائِهِ', 'And to Allah belong the most beautiful names, so call on Him by them, and leave those who deviate concerning His names.', 'Surah al-A''raf 7:180', 1);
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('categories-of-tawheed--asma-wa-sifat--p2', 'categories-of-tawheed--asma-wa-sifat', 'quran', 'لَيْسَ كَمِثْلِهِ شَيْءٌ ۖ وَهُوَ السَّمِيعُ الْبَصِيرُ', 'There is nothing like Him, and He is the Hearing, the Seeing.', 'Surah ash-Shura 42:11', 2);
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('categories-of-tawheed--asma-wa-sifat--p3', 'categories-of-tawheed--asma-wa-sifat', 'hadith', 'إِنَّ لِلَّهِ تِسْعَةً وَتِسْعِينَ اسْمًا، مِائَةً إِلاَّ وَاحِدًا، مَنْ أَحْصَاهَا دَخَلَ الْجَنَّةَ', 'Allah has ninety-nine names — one hundred less one. Whoever enumerates them enters Paradise.', 'Sahih al-Bukhari #2736; Sahih Muslim #2677', 3);
insert into public.videos (id, lesson_id, youtube_url, title, scholar, topic) values ('video-categories-of-tawheed--asma-wa-sifat', 'categories-of-tawheed--asma-wa-sifat', 'https://www.youtube.com/watch?v=8mL4qaGY5yQ', '3 Types of Tawheed in Detail', 'Shaykh Salih al-Fawzan', 'Tawheed al-Asma wa''s-Sifat: Names and Attributes');
insert into public.lessons (id, module_id, slug, title, content_html, display_order, video_youtube_url, video_scholar, video_title, book_recommendations, based_on) values ('categories-of-tawheed--shirk', 'categories-of-tawheed', 'what-nullifies-tawheed', 'What Nullifies Tawheed: Shirk and Its Categories', 'Having learned what tawheed is, you must learn what destroys it. **Shirk**, associating partners with Allah in what belongs to Him alone, is the greatest sin with which Allah is disobeyed. It is the one sin Allah says He will not forgive if a person dies upon it without repentance:
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('categories-of-tawheed--shirk--p1', 'categories-of-tawheed--shirk', 'quran', 'إِنَّ اللَّهَ لَا يَغْفِرُ أَن يُشْرَكَ بِهِ وَيَغْفِرُ مَا دُونَ ذَٰلِكَ لِمَن يَشَاءُ', 'Indeed, Allah does not forgive that partners be associated with Him, but He forgives what is less than that for whom He wills.', 'Surah an-Nisa 4:48', 1);
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('categories-of-tawheed--shirk--p2', 'categories-of-tawheed--shirk', 'quran', 'يَا بُنَيَّ لَا تُشْرِكْ بِاللَّهِ ۖ إِنَّ الشِّرْكَ لَظُلْمٌ عَظِيمٌ', 'O my son, do not associate anything with Allah. Indeed, shirk is a tremendous injustice.', 'Surah Luqman 31:13', 2);
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('categories-of-tawheed--shirk--p3', 'categories-of-tawheed--shirk', 'hadith', 'مَنْ مَاتَ وَهُوَ يَدْعُو مِنْ دُونِ اللَّهِ نِدًّا دَخَلَ النَّارَ', 'Whoever dies while calling upon a rival besides Allah enters the Fire.', 'Sahih al-Bukhari #4497', 3);
insert into public.videos (id, lesson_id, youtube_url, title, scholar, topic) values ('video-categories-of-tawheed--shirk', 'categories-of-tawheed--shirk', 'https://www.youtube.com/watch?v=xSK94KMy_ec', 'The Categories of Shirk and Which One Exits You from Islam', 'Shaykh Salih al-Fawzan', 'What Nullifies Tawheed: Shirk and Its Categories');
insert into public.lessons (id, module_id, slug, title, content_html, display_order, video_youtube_url, video_scholar, video_title, book_recommendations, based_on) values ('qawaid-al-arba--first-principle', 'qawaid-al-arba', 'first-principle', 'Introduction and the First Principle', '**Al-Qawa''id al-Arba''** (The Four Principles) is a short text on shirk, barely a page, yet it removes the most common confusions about it. The author opens with a du''a for the reader: *I ask Allah, the Generous, Lord of the Great Throne, to befriend you in this world and the next, to make you blessed wherever you are, and to make you of those who when given are grateful, when tested are patient, and when they sin seek forgiveness, for these three are the signs of happiness.*
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('qawaid-al-arba--first-principle--p1', 'qawaid-al-arba--first-principle', 'quran', 'قُلْ مَن يَرْزُقُكُم مِّنَ السَّمَاءِ وَالْأَرْضِ أَمَّن يَمْلِكُ السَّمْعَ وَالْأَبْصَارَ وَمَن يُخْرِجُ الْحَيَّ مِنَ الْمَيِّتِ وَيُخْرِجُ الْمَيِّتَ مِنَ الْحَيِّ وَمَن يُدَبِّرُ الْأَمْرَ ۚ فَسَيَقُولُونَ اللَّهُ ۚ فَقُلْ أَفَلَا تَتَّقُونَ', 'Say: who provides for you from the heaven and the earth? Or who controls hearing and sight? And who brings the living out of the dead and the dead out of the living? And who disposes of every affair? They will say, ''Allah.'' So say: will you not then fear Him?', 'Surah Yunus 10:31', 1);
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('qawaid-al-arba--first-principle--p2', 'qawaid-al-arba--first-principle', 'quran', 'وَمَا يُؤْمِنُ أَكْثَرُهُم بِاللَّهِ إِلَّا وَهُم مُّشْرِكُونَ', 'And most of them do not believe in Allah except while they associate others with Him.', 'Surah Yusuf 12:106', 2);
insert into public.videos (id, lesson_id, youtube_url, title, scholar, topic) values ('video-qawaid-al-arba--first-principle', 'qawaid-al-arba--first-principle', 'https://www.youtube.com/watch?v=C97kF9uqatQ', 'The Importance of the Four Principles', 'Shaykh Salih al-Fawzan', 'Introduction and the First Principle');
insert into public.lessons (id, module_id, slug, title, content_html, display_order, video_youtube_url, video_scholar, video_title, book_recommendations, based_on) values ('qawaid-al-arba--second-and-third', 'qawaid-al-arba', 'second-and-third-principles', 'The Second and Third Principles: ''Nearness'' and ''Intercession''', '**The Second Principle** answers the excuse the mushrikun themselves offered. They did not say “our idols created us.” They said: we only worship them *to draw near* to Allah, and *to intercede* for us with Him. The Quran records their own words:
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('qawaid-al-arba--second-and-third--p1', 'qawaid-al-arba--second-and-third', 'quran', 'وَالَّذِينَ اتَّخَذُوا مِن دُونِهِ أَوْلِيَاءَ مَا نَعْبُدُهُمْ إِلَّا لِيُقَرِّبُونَا إِلَى اللَّهِ زُلْفَىٰ', 'And those who take protectors besides Him [say]: ''We only worship them that they may bring us nearer to Allah in position.''', 'Surah az-Zumar 39:3', 1);
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('qawaid-al-arba--second-and-third--p2', 'qawaid-al-arba--second-and-third', 'quran', 'وَيَعْبُدُونَ مِن دُونِ اللَّهِ مَا لَا يَضُرُّهُمْ وَلَا يَنفَعُهُمْ وَيَقُولُونَ هَٰؤُلَاءِ شُفَعَاؤُنَا عِندَ اللَّهِ', 'And they worship besides Allah that which neither harms them nor benefits them, and they say: ''These are our intercessors with Allah.''', 'Surah Yunus 10:18', 2);
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('qawaid-al-arba--second-and-third--p3', 'qawaid-al-arba--second-and-third', 'quran', 'وَاسْأَلْ مَنْ أَرْسَلْنَا مِن قَبْلِكَ مِن رُّسُلِنَا أَجَعَلْنَا مِن دُونِ الرَّحْمَٰنِ آلِهَةً يُعْبَدُونَ', 'And ask those We sent before you of Our messengers: did We ever appoint gods to be worshipped besides the Most Merciful?', 'Surah az-Zukhruf 43:45', 3);
insert into public.videos (id, lesson_id, youtube_url, title, scholar, topic) values ('video-qawaid-al-arba--second-and-third', 'qawaid-al-arba--second-and-third', 'https://www.youtube.com/watch?v=C97kF9uqatQ', 'The Importance of the Four Principles', 'Shaykh Salih al-Fawzan', 'The Second and Third Principles: ''Nearness'' and ''Intercession''');
insert into public.lessons (id, module_id, slug, title, content_html, display_order, video_youtube_url, video_scholar, video_title, book_recommendations, based_on) values ('qawaid-al-arba--fourth-principle', 'qawaid-al-arba', 'fourth-principle', 'The Fourth Principle: The Shirk of Ease and the Shirk of Hardship', '**The Fourth Principle:** the mushrikun of the Prophet''s ﷺ era called upon their idols and intermediaries in ease, but when the sea surrounded them and they feared drowning, they abandoned every partner and called upon Allah alone, sincere to Him in the religion:
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('qawaid-al-arba--fourth-principle--p1', 'qawaid-al-arba--fourth-principle', 'quran', 'فَإِذَا رَكِبُوا فِي الْفُلْكِ دَعَوُا اللَّهَ مُخْلِصِينَ لَهُ الدِّينَ فَلَمَّا نَجَّاهُمْ إِلَى الْبَرِّ إِذَا هُمْ يُشْرِكُونَ', 'And when they board a ship, they call upon Allah, making their religion sincerely His; but when He delivers them to the land, at once they associate others with Him.', 'Surah al-Ankabut 29:65', 1);
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('qawaid-al-arba--fourth-principle--p2', 'qawaid-al-arba--fourth-principle', 'quran', 'وَمَا أُمِرُوا إِلَّا لِيَعْبُدُوا اللَّهَ مُخْلِصِينَ لَهُ الدِّينَ حُنَفَاءَ', 'And they were not commanded except to worship Allah, making the religion sincerely His, inclining to truth.', 'Surah al-Bayyinah 98:5', 2);
insert into public.videos (id, lesson_id, youtube_url, title, scholar, topic) values ('video-qawaid-al-arba--fourth-principle', 'qawaid-al-arba--fourth-principle', 'https://www.youtube.com/watch?v=C97kF9uqatQ', 'The Importance of the Four Principles', 'Shaykh Salih al-Fawzan', 'The Fourth Principle: The Shirk of Ease and the Shirk of Hardship');
insert into public.lessons (id, module_id, slug, title, content_html, display_order, video_youtube_url, video_scholar, video_title, book_recommendations, based_on) values ('nawaqid-al-islam--first-five', 'nawaqid-al-islam', 'first-five-nullifiers', 'What Nullifies Islam, and the First Five Nullifiers', 'A person can enter Islam with a sincere testimony and then do something that cancels it, as ablution is nullified by what breaks it. Shaykh Muhammad ibn Abd al-Wahhab gathered **ten nullifiers** (nawaqid) of Islam so that a Muslim would know them and stay far from them. This chapter is not for declaring others disbelievers; that is the work of the scholars, with its conditions and barriers. It is for **guarding your own Islam**, for knowing what destroys a thing is part of protecting it.
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('nawaqid-al-islam--first-five--p1', 'nawaqid-al-islam--first-five', 'quran', 'إِنَّ اللَّهَ لَا يَغْفِرُ أَن يُشْرَكَ بِهِ وَيَغْفِرُ مَا دُونَ ذَٰلِكَ لِمَن يَشَاءُ', 'Indeed, Allah does not forgive that partners be associated with Him, but He forgives what is less than that for whom He wills.', 'Surah an-Nisa 4:48', 1);
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('nawaqid-al-islam--first-five--p2', 'nawaqid-al-islam--first-five', 'quran', 'فَلَا وَرَبِّكَ لَا يُؤْمِنُونَ حَتَّىٰ يُحَكِّمُوكَ فِيمَا شَجَرَ بَيْنَهُمْ ثُمَّ لَا يَجِدُوا فِي أَنفُسِهِمْ حَرَجًا مِّمَّا قَضَيْتَ وَيُسَلِّمُوا تَسْلِيمًا', 'But no, by your Lord, they will not believe until they make you judge concerning that which arises between them, then find within themselves no discomfort from what you have judged, and submit in full submission.', 'Surah an-Nisa 4:65', 2);
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('nawaqid-al-islam--first-five--p3', 'nawaqid-al-islam--first-five', 'quran', 'ذَٰلِكَ بِأَنَّهُمْ كَرِهُوا مَا أَنزَلَ اللَّهُ فَأَحْبَطَ أَعْمَالَهُمْ', 'That is because they hated what Allah revealed, so He rendered their deeds worthless.', 'Surah Muhammad 47:9', 3);
insert into public.videos (id, lesson_id, youtube_url, title, scholar, topic) values ('video-nawaqid-al-islam--first-five', 'nawaqid-al-islam--first-five', 'https://www.youtube.com/watch?v=ZVyt3iufvbc&list=PLcNmEBnwyvx5osgWR-7AsrHoh0X9ffGC6', 'The Nullifiers of Islam (lesson series)', 'Ustadh Abu Hakeem Bilal Davis', 'What Nullifies Islam, and the First Five Nullifiers');
insert into public.lessons (id, module_id, slug, title, content_html, display_order, video_youtube_url, video_scholar, video_title, book_recommendations, based_on) values ('nawaqid-al-islam--second-five', 'nawaqid-al-islam', 'second-five-nullifiers', 'The Second Five Nullifiers', '**The Sixth Nullifier: mocking something of the religion of the Messenger ﷺ**: mocking Allah, or the Quran, or the Messenger ﷺ, or the reward or the punishment. Some men at Tabuk joked about the reciters, and Allah revealed concerning them:
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('nawaqid-al-islam--second-five--p1', 'nawaqid-al-islam--second-five', 'quran', 'قُلْ أَبِاللَّهِ وَآيَاتِهِ وَرَسُولِهِ كُنتُمْ تَسْتَهْزِئُونَ ۝ لَا تَعْتَذِرُوا قَدْ كَفَرْتُم بَعْدَ إِيمَانِكُمْ', 'Say: was it Allah, and His verses, and His Messenger that you were mocking? Make no excuse; you have disbelieved after your belief.', 'Surah at-Tawbah 9:65-66', 1);
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('nawaqid-al-islam--second-five--p2', 'nawaqid-al-islam--second-five', 'quran', 'وَمَا يُعَلِّمَانِ مِنْ أَحَدٍ حَتَّىٰ يَقُولَا إِنَّمَا نَحْنُ فِتْنَةٌ فَلَا تَكْفُرْ', 'But the two angels do not teach anyone until they say: we are only a trial, so do not disbelieve.', 'Surah al-Baqarah 2:102', 2);
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('nawaqid-al-islam--second-five--p3', 'nawaqid-al-islam--second-five', 'quran', 'وَمَن يَتَوَلَّهُم مِّنكُمْ فَإِنَّهُ مِنْهُمْ ۗ إِنَّ اللَّهَ لَا يَهْدِي الْقَوْمَ الظَّالِمِينَ', 'And whoever among you takes them as allies — then indeed, he is one of them. Indeed, Allah does not guide the wrongdoing people.', 'Surah al-Ma''idah 5:51', 3);
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('nawaqid-al-islam--second-five--p4', 'nawaqid-al-islam--second-five', 'quran', 'وَمَنْ أَظْلَمُ مِمَّن ذُكِّرَ بِآيَاتِ رَبِّهِ ثُمَّ أَعْرَضَ عَنْهَا ۚ إِنَّا مِنَ الْمُجْرِمِينَ مُنتَقِمُونَ', 'And who is more unjust than one who is reminded of the verses of his Lord, then turns away from them? Indeed, We will take retribution from the criminals.', 'Surah as-Sajdah 32:22', 4);
insert into public.videos (id, lesson_id, youtube_url, title, scholar, topic) values ('video-nawaqid-al-islam--second-five', 'nawaqid-al-islam--second-five', 'https://www.youtube.com/watch?v=ZVyt3iufvbc&list=PLcNmEBnwyvx5osgWR-7AsrHoh0X9ffGC6', 'The Nullifiers of Islam (lesson series)', 'Ustadh Abu Hakeem Bilal Davis', 'The Second Five Nullifiers');
insert into public.lessons (id, module_id, slug, title, content_html, display_order, video_youtube_url, video_scholar, video_title, book_recommendations, based_on) values ('usul-al-sittah--first-three', 'usul-al-sittah', 'first-three-foundations', 'The First Three Foundations: Sincerity, Unity, and Obedience', 'The author opens this short treatise with these words: these are **six foundations that Allah made so clear that even the common, unlettered person can grasp them**, yet most people, including many who claim knowledge, fell into the opposite of them. Each foundation follows one pattern: Allah made the matter plain, and the majority opposed it.
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('usul-al-sittah--first-three--p1', 'usul-al-sittah--first-three', 'quran', 'وَمَا أُمِرُوا إِلَّا لِيَعْبُدُوا اللَّهَ مُخْلِصِينَ لَهُ الدِّينَ حُنَفَاءَ', 'And they were not commanded except to worship Allah, making the religion sincerely His, inclining to truth.', 'Surah al-Bayyinah 98:5', 1);
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('usul-al-sittah--first-three--p2', 'usul-al-sittah--first-three', 'quran', 'وَاعْتَصِمُوا بِحَبْلِ اللَّهِ جَمِيعًا وَلَا تَفَرَّقُوا', 'And hold firmly to the rope of Allah all together, and do not become divided.', 'Surah Aal Imran 3:103', 2);
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('usul-al-sittah--first-three--p3', 'usul-al-sittah--first-three', 'quran', 'يَا أَيُّهَا الَّذِينَ آمَنُوا أَطِيعُوا اللَّهَ وَأَطِيعُوا الرَّسُولَ وَأُولِي الْأَمْرِ مِنكُمْ', 'O you who believe, obey Allah and obey the Messenger and those in authority among you.', 'Surah an-Nisa 4:59', 3);
insert into public.videos (id, lesson_id, youtube_url, title, scholar, topic) values ('video-usul-al-sittah--first-three', 'usul-al-sittah--first-three', 'https://www.youtube.com/watch?v=z1xm_qhEdsc', 'Usool as-Sittah — Full Explanation', 'Shaykh Dr. Muhammad al-Hujayli', 'The First Three Foundations: Sincerity, Unity, and Obedience');
insert into public.lessons (id, module_id, slug, title, content_html, display_order, video_youtube_url, video_scholar, video_title, book_recommendations, based_on) values ('usul-al-sittah--last-three', 'usul-al-sittah', 'last-three-foundations', 'The Last Three Foundations: The Scholars, the Allies of Allah, and the Great Doubt', '**The Fourth Foundation: clarifying who the scholars (ulama) truly are.** Knowledge in Islam is not a costume or a title; the scholar is the one who fears Allah because he *knows* Him, and who inherits the guidance of the prophets. Allah defined the people of real knowledge by their fear of Him:
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('usul-al-sittah--last-three--p1', 'usul-al-sittah--last-three', 'quran', 'إِنَّمَا يَخْشَى اللَّهَ مِنْ عِبَادِهِ الْعُلَمَاءُ ۗ إِنَّ اللَّهَ عَزِيزٌ غَفُورٌ', 'Only those who have knowledge among His servants fear Allah. Indeed, Allah is Exalted in Might, Forgiving.', 'Surah Fatir 35:28', 1);
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('usul-al-sittah--last-three--p2', 'usul-al-sittah--last-three', 'quran', 'أَلَا إِنَّ أَوْلِيَاءَ اللَّهِ لَا خَوْفٌ عَلَيْهِمْ وَلَا هُمْ يَحْزَنُونَ ۝ الَّذِينَ آمَنُوا وَكَانُوا يَتَّقُونَ', 'Unquestionably, the allies of Allah — there will be no fear upon them, nor will they grieve: those who believed and were fearing Allah.', 'Surah Yunus 10:62-63', 2);
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('usul-al-sittah--last-three--p3', 'usul-al-sittah--last-three', 'quran', 'وَنَزَّلْنَا عَلَيْكَ الْكِتَابَ تِبْيَانًا لِّكُلِّ شَيْءٍ وَهُدًى وَرَحْمَةً وَبُشْرَىٰ لِلْمُسْلِمِينَ', 'And We have sent down to you the Book as a clarification for all things, and as guidance and mercy and good tidings for the Muslims.', 'Surah an-Nahl 16:89', 3);
insert into public.videos (id, lesson_id, youtube_url, title, scholar, topic) values ('video-usul-al-sittah--last-three', 'usul-al-sittah--last-three', 'https://www.youtube.com/watch?v=z1xm_qhEdsc', 'Usool as-Sittah — Full Explanation', 'Shaykh Dr. Muhammad al-Hujayli', 'The Last Three Foundations: The Scholars, the Allies of Allah, and the Great Doubt');
insert into public.lessons (id, module_id, slug, title, content_html, display_order, video_youtube_url, video_scholar, video_title, book_recommendations, based_on) values ('kashf-al-shubuhat--two-tawheeds', 'kashf-al-shubuhat', 'the-doubt-at-the-root', 'The Doubt at the Root: The Tawheed They Affirmed and the Tawheed They Denied', 'You have learned *what* tawheed is. **Kashf al-Shubuhat** ("Removal of the Doubts") teaches you to defend it by answering the arguments raised against it. The author wrote it because a person may know tawheed and still be shaken when a doubt is presented well. So learn the truth, and learn where each objection fails.
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('kashf-al-shubuhat--two-tawheeds--p1', 'kashf-al-shubuhat--two-tawheeds', 'quran', 'وَلَئِن سَأَلْتَهُم مَّنْ خَلَقَ السَّمَاوَاتِ وَالْأَرْضَ لَيَقُولُنَّ اللَّهُ ۚ قُلِ الْحَمْدُ لِلَّهِ ۚ بَلْ أَكْثَرُهُمْ لَا يَعْلَمُونَ', 'And if you asked them who created the heavens and the earth, they would surely say, ''Allah.'' Say: all praise is due to Allah. But most of them do not know.', 'Surah Luqman 31:25', 1);
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('kashf-al-shubuhat--two-tawheeds--p2', 'kashf-al-shubuhat--two-tawheeds', 'quran', 'وَلَقَدْ بَعَثْنَا فِي كُلِّ أُمَّةٍ رَّسُولًا أَنِ اعْبُدُوا اللَّهَ وَاجْتَنِبُوا الطَّاغُوتَ', 'And We certainly sent into every nation a messenger, [saying]: worship Allah and avoid taghut.', 'Surah an-Nahl 16:36', 2);
insert into public.videos (id, lesson_id, youtube_url, title, scholar, topic) values ('video-kashf-al-shubuhat--two-tawheeds', 'kashf-al-shubuhat--two-tawheeds', 'https://www.youtube.com/watch?v=e8YnfLXHqsg', 'Kashf ash-Shubuhat — Full Explanation', 'Shaykh Haytham Sarhan', 'The Doubt at the Root: The Tawheed They Affirmed and the Tawheed They Denied');
insert into public.lessons (id, module_id, slug, title, content_html, display_order, video_youtube_url, video_scholar, video_title, book_recommendations, based_on) values ('kashf-al-shubuhat--intercession', 'kashf-al-shubuhat', 'answering-the-doubts', 'Answering the Doubts: Nearness, Intercession, and the Righteous', '**The greatest doubt: "We do not believe these beings create or provide. We only turn to them so they bring us nearer to Allah, and intercede for us with Him."** The author''s answer is devastating in its simplicity: *this is word-for-word the excuse of the original mushrikun.* The Quran did not report it to excuse them; it reported it to condemn them:
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('kashf-al-shubuhat--intercession--p1', 'kashf-al-shubuhat--intercession', 'quran', 'وَالَّذِينَ اتَّخَذُوا مِن دُونِهِ أَوْلِيَاءَ مَا نَعْبُدُهُمْ إِلَّا لِيُقَرِّبُونَا إِلَى اللَّهِ زُلْفَىٰ', 'And those who take protectors besides Him [say]: ''We only worship them that they may bring us nearer to Allah in position.''', 'Surah az-Zumar 39:3', 1);
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('kashf-al-shubuhat--intercession--p2', 'kashf-al-shubuhat--intercession', 'quran', 'قُل لِّلَّهِ الشَّفَاعَةُ جَمِيعًا ۖ لَّهُ مُلْكُ السَّمَاوَاتِ وَالْأَرْضِ', 'Say: to Allah belongs [the right to allow] all intercession. To Him belongs the dominion of the heavens and the earth.', 'Surah az-Zumar 39:44', 2);
insert into public.proofs (id, lesson_id, type, arabic_text, english_translation, reference, display_order) values ('kashf-al-shubuhat--intercession--p3', 'kashf-al-shubuhat--intercession', 'quran', 'أُولَٰئِكَ الَّذِينَ يَدْعُونَ يَبْتَغُونَ إِلَىٰ رَبِّهِمُ الْوَسِيلَةَ أَيُّهُمْ أَقْرَبُ وَيَرْجُونَ رَحْمَتَهُ وَيَخَافُونَ عَذَابَهُ', 'Those whom they invoke are themselves seeking the means of nearness to their Lord — which of them is nearest — and hoping for His mercy and fearing His punishment.', 'Surah al-Isra 17:57', 3);
insert into public.videos (id, lesson_id, youtube_url, title, scholar, topic) values ('video-kashf-al-shubuhat--intercession', 'kashf-al-shubuhat--intercession', 'https://www.youtube.com/watch?v=e8YnfLXHqsg', 'Kashf ash-Shubuhat — Full Explanation', 'Shaykh Haytham Sarhan', 'Answering the Doubts: Nearness, Intercession, and the Righteous');
insert into public.quizzes (id, module_id) values ('quiz-introduction', 'introduction');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-in-01', 'quiz-introduction', 'What is ikhlas, as this introduction defines it?', '["Purifying the intention so that learning and worship are for Allah''s face alone","Performing acts of worship with technical precision and correct form","Concealing all of one''s good deeds from every other person","Learning the religion from many teachers to avoid bias"]'::jsonb, 0, 'Ikhlas is sincerity of intention — seeking Allah, not appearance or applause. Concealing deeds can help protect sincerity but is not its definition; a public deed done for Allah remains sincere.', 'ikhlas', 'recall');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-in-02', 'quiz-introduction', 'Why did Imam al-Bukhari open his Sahih with the hadith ''Actions are only by intentions''?', '["Because it was the first hadith he ever memorized as a child","Because it has the shortest chain of narration in his collection","Because every deed in the book that follows — and every deed in a Muslim''s life — is weighed by the intention behind it","Because scholars of his time disputed its authenticity"]'::jsonb, 2, 'Placing the intention-hadith first announces that everything after it depends on the heart''s purpose. The same act of learning can raise a person or ruin him — the difference lives in the intention (Sahih Muslim #1905 warns of the man who learned so it would be said ''he is a scholar'').', 'ikhlas', 'application');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-in-03', 'quiz-introduction', 'A student says: ''I''ve begun studying aqeedah; the results now depend entirely on how hard I work.'' What correction does the second lesson give?', '["None — effort is indeed the sole cause of guidance","Take the means fully, but guidance itself is given by Allah — so pair effort with du''a and reliance","Effort is irrelevant since guidance was decreed long ago","Hard work matters only after mastering the Arabic language"]'::jsonb, 1, '''Indeed, you do not guide whom you love, but Allah guides whom He wills'' (al-Qasas 28:56). The student takes the means — reading, listening, asking — while depending on Allah for the outcome. Abandoning effort is fatalism; trusting effort alone forgets who holds the hearts.', 'guidance', 'application');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-in-04', 'quiz-introduction', 'What does the placement of ''Guide us to the straight path'' in every rak''ah of prayer teach about guidance?', '["That guidance is needed constantly and must be asked for continually, not acquired once","That the du''a is meant only for those who have not yet accepted Islam","That guidance is granted automatically to whoever prays","That the straight path refers only to physical direction of the qiblah"]'::jsonb, 0, 'Allah obligated the request at least seventeen times a day — because hearts turn, and remaining guided is a continuous need. The hadith qudsi confirms it: ''All of you are astray except those whom I guide, so seek guidance from Me'' (Sahih Muslim #2577).', 'guidance', 'analysis');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-in-05', 'quiz-introduction', 'What is tawakkul, as paired with study in this introduction?', '["Abandoning planning so that Allah''s decree operates unhindered","Relying on the strength of one''s teachers and study materials","Postponing study until one feels spiritually ready","Taking the means fully while depending on Allah for the result"]'::jsonb, 3, '''Whoever relies upon Allah — He is sufficient for him'' (at-Talaq 65:3). Tawakkul is not abandoning means; it is working as if everything depends on the means while knowing the outcome belongs to Allah alone.', 'guidance', 'recall');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-in-06', 'quiz-introduction', 'According to Sahih Muslim #2699, what does Allah make easy for the one who treads a path seeking knowledge?', '["Provision and wealth in this world","A path to Paradise","Victory over opponents in debate","Memorization of everything he reads"]'::jsonb, 1, '''Whoever treads a path seeking knowledge in it, Allah makes easy for him thereby a path to Paradise.'' The reward named is the greatest one — and it hangs the honour of seeking ilm on the destination it leads to.', 'seeking-ilm', 'recall');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-in-07', 'quiz-introduction', 'The only increase the Prophet ﷺ was commanded to ask for in the Quran was:', '["Increase in followers","Increase in provision","Increase in knowledge","Increase in lifespan"]'::jsonb, 2, '''And say: My Lord, increase me in knowledge'' (Ta-Ha 20:114). The scholars note that of all things Allah could have commanded His Prophet ﷺ to seek more of, He chose ilm — a measure of its rank above every worldly increase.', 'seeking-ilm', 'recall');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-in-08', 'quiz-introduction', 'A new student plans to finish all nine modules in one weekend. Which counsel from the third lesson does this collide with?', '["Learning with proof — he has not verified the site''s references yet","Learning for action — he has not implemented anything yet","Learning in order — he intends to study the modules out of sequence","Learning gradually — whoever seizes knowledge all at once loses it all at once, and constant small deeds are most beloved to Allah"]'::jsonb, 3, 'Knowledge settles a little at a time; cramming produces familiarity, not firmness. The most beloved deeds to Allah are the most constant even if small (Sahih al-Bukhari #6464) — which is why the site plans single daily lessons rather than marathons.', 'seeking-ilm', 'application');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-in-09', 'quiz-introduction', 'Why does the curriculum insist on a proof under every claim rather than asking you to trust the site?', '["So the pages look more scholarly to visitors","So your creed rests on revelation — the ayah and the hadith — rather than on any website or personality","Because proofs are required by publishing law","So that quizzes have material to test"]'::jsonb, 1, 'The manhaj of this library is that belief follows evidence. A creed built on a website collapses with the website; a creed tied to the Quran and Sunnah stands. Check the proofs and ask the people of knowledge.', 'seeking-ilm', 'application');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-in-10', 'quiz-introduction', 'Sufyan ath-Thawri said he never treated anything more difficult than his intention. What practical habit does the first lesson draw from this?', '["Delay studying until the intention feels perfectly pure","Renew and inspect the intention repeatedly, because it keeps turning","Announce one''s intention publicly for accountability","Study only in private so intention cannot be corrupted"]'::jsonb, 1, 'Intentions drift, so they are renewed — before study, during it, and on returning to it. Waiting for a perfect heart before acting is a trick that stops the deed; the Salaf acted and watched their hearts as they went.', 'ikhlas', 'application');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-in-11', 'quiz-introduction', '''When Allah wants good for a person, He gives him understanding of the religion'' (al-Bukhari #71). How does the introduction apply this to you as a beginning student?', '["It guarantees that every student will become a scholar","It means formal study is unnecessary since understanding is a gift","Your desire to learn is itself a door Allah opened — enter it with gratitude and effort, not complacency","It applies only to those born into families of scholars"]'::jsonb, 2, 'The hadith makes fiqh in the religion a sign of Allah''s good intent for a person. Finding yourself at the start of this path is a blessing to act upon — the gift invites effort rather than replacing it.', 'seeking-ilm', 'analysis');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-in-12', 'quiz-introduction', 'Taken together, what do the three introduction lessons say must be in place before the first module?', '["Fluent Arabic, a personal teacher, and a complete library","A purified intention, reliance on Allah for guidance, and a sound method of seeking knowledge","Memorization of the Quran and the six books of hadith","A fixed daily schedule of at least three hours"]'::jsonb, 1, 'The sequence is deliberate: ikhlas (why you learn), then guidance and tawakkul (from whom it comes), then the virtue and manners of seeking ilm (how to walk the path). With these three, the student is ready for the Five Pillars.', 'overview', 'analysis');
insert into public.quizzes (id, module_id) values ('quiz-five-pillars', 'five-pillars');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-fp-01', 'quiz-five-pillars', 'In the hadith of Jibreel, who was the questioner, and why did he ask questions he already knew the answers to?', '["A bedouin testing the Prophet ﷺ, because the desert Arabs doubted his message until they heard it face to face","The angel Jibreel in the form of a man, so that the Companions would hear the religion defined by question and answer","Abu Bakr, because the Prophet ﷺ instructed his closest Companion to ask on behalf of the newer Muslims","A delegation from Yemen, since the people of Yemen were known for asking the most precise questions about faith"]'::jsonb, 1, 'The Prophet ﷺ said at the end of the narration: “That was Jibreel; he came to teach you your religion” (Sahih Muslim #8). The questioning format was deliberate teaching, not genuine inquiry — which is why the Prophet ﷺ noted the strangeness of a questioner who confirms each answer. The bedouin option is tempting because bedouins did question the Prophet ﷺ in other narrations, but not this one.', 'hadith-jibreel', 'recall');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-fp-02', 'quiz-five-pillars', 'The phrase “la ilaha illa Allah” contains a negation and an affirmation. What exactly is being negated?', '["The existence of any beings that people treat as gods","The possibility of knowing anything about Allah except through reason","The right of anything besides Allah to be worshipped","The value of intermediaries in bringing people to correct belief"]'::jsonb, 2, 'The kalimah negates the *right* to worship, not the existence of false gods — idols and tyrants exist, but none deserve worship. This is why the scholars translate it “none has the right to be worshipped except Allah” rather than “there is no god but Allah” alone. Misreading it as denying existence is the most common error, since false objects of worship plainly exist while deserving nothing.', 'shahadatayn', 'application');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-fp-03', 'quiz-five-pillars', 'A friend says: “I bear witness that Muhammad is the Messenger of Allah — but the sunnah prayers and his way of dress were just seventh-century culture, so I only take the Quran.” Which requirement of the second testimony is he missing?', '["Believing the Prophet''s ﷺ reports about the unseen world","Loving the Prophet ﷺ more than one''s own family and possessions","Defending the Prophet''s ﷺ honour when he is insulted","Worshipping Allah only in the way the Prophet ﷺ legislated"]'::jsonb, 3, 'Testifying to messengership obligates obeying his commands, believing his reports, avoiding what he forbade, and worshipping Allah by his legislation — his Sunnah defines *how* worship is done. “Whoever obeys the Messenger has obeyed Allah” (an-Nisa 4:80). The other options are real obligations too, but the scenario describes someone specifically rejecting the Sunnah as a source of practice.', 'shahadatayn', 'application');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-fp-04', 'quiz-five-pillars', 'Why did the Prophet ﷺ instruct Mu''adh ibn Jabal to begin with the shahadah when calling the People of the Book in Yemen, rather than beginning with prayer or charity?', '["No deed is accepted without correct belief, so the foundation must precede the structure","The People of the Book were exempt from the other pillars until they mastered theology","Prayer and charity were not yet legislated at the time Mu''adh was sent to Yemen","The shahadah was easier to accept, and da''wah should always start with the easiest matter"]'::jsonb, 0, 'The hadith (al-Bukhari #1496) orders the call: tawheed first, then prayer, then zakah — because worship built on shirk is a building without a foundation. The “easiest first” option is the tempting one, but the shahadah was actually the *hardest* demand for that audience; it was placed first for validity, not ease. Prayer and zakah were long since legislated by that late Madinan period.', 'shahadatayn', 'analysis');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-fp-05', 'quiz-five-pillars', 'What does “establishing the prayer” (iqamat as-salah) add beyond simply performing it?', '["Praying extra voluntary prayers alongside the obligatory ones each day","Performing it with its conditions, pillars and times — built properly like a structure","Attending the mosque for every single prayer without any exception","Reciting longer portions of the Quran and lengthening the prostrations"]'::jsonb, 1, 'The Quran''s word iqamah (establishing) implies raising something upright and complete: on time, with purification, humility, and its essential parts. A rushed, delayed or hollow prayer is “performed” but not “established.” Congregation and voluntary prayers are virtues connected to it, but the term itself concerns the quality and completeness of the obligatory act.', 'salah', 'application');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-fp-06', 'quiz-five-pillars', 'Which statement did the Prophet ﷺ make about the one who abandons the prayer?', '["His fasting and charity carry his prayer''s reward until he returns to it","He remains a Muslim as long as belief stays firmly in his heart","His case is delayed to the Day of Judgment with no ruling in this world","Between a man and shirk and disbelief stands the abandonment of the prayer"]'::jsonb, 3, 'The wording is from Sahih Muslim #82. The Companions treated abandoning salah with unmatched severity — Abdullah ibn Shaqiq relates they considered no other deed''s abandonment to be kufr. Option two reflects the common “faith is in the heart” reassurance, which is precisely the assumption this hadith confronts.', 'salah', 'recall');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-fp-07', 'quiz-five-pillars', 'Zakah is best described as which of the following?', '["A voluntary charity that generous Muslims give when they can afford it","A government tax that Islamic states may adjust according to public need","A fixed annual right owed on qualifying wealth, purifying the giver and his property","A one-time payment made upon entering Islam to establish membership in the community"]'::jsonb, 2, 'Allah commands: “Take from their wealth a charity by which you purify them” (at-Tawbah 9:103) — a defined right (2.5% on stored monetary wealth), not generosity left to mood or state policy. Confusing zakah with voluntary sadaqah is the most common error; sadaqah is open-ended, while zakah has thresholds, rates and recipients fixed by revelation.', 'zakah', 'recall');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-fp-08', 'quiz-five-pillars', 'A Muslim with savings well above the nisab says: “I gave generously to a mosque construction project this year, so my zakah is covered.” What is the correct assessment?', '["His donation counts because building mosques is among the eight categories of zakah recipients","Voluntary giving does not discharge zakah, which must be calculated and paid as its own obligation","His donation counts as long as he made the intention of zakah at any point before the year ended","Zakah does not apply to savings, only to business inventory, so nothing was due in the first place"]'::jsonb, 1, 'Zakah is a specific obligation with a specific intention, calculation and recipients (at-Tawbah 9:60 lists them — general mosque construction is not among the eight). A gift given as ordinary sadaqah cannot be retroactively relabeled. The principle: obligatory worship is defined by the Legislator, not offset by voluntary good elsewhere.', 'zakah', 'application');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-fp-09', 'quiz-five-pillars', 'According to Surah al-Baqarah 2:183, what is the stated purpose of fasting Ramadan?', '["Attaining taqwa","Learning to feel the hunger of the poor so that society becomes more generous","Purifying the body through an annual period of physical discipline","Earning multiplied rewards during the month the Quran was revealed"]'::jsonb, 0, 'The ayah ends “la''allakum tattaqun” — that you may attain taqwa, mindfulness of Allah. Empathy for the poor and physical benefits are real side-fruits mentioned by some scholars, but the Quran states the objective as taqwa: fasting trains the soul to obey Allah against its appetites. Note how the shortest option is correct here — length is no guide.', 'sawm', 'recall');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-fp-10', 'quiz-five-pillars', 'A colleague fasts Ramadan but spends the day deceiving customers, and says “fasting is between me and food, business is business.” Which prophetic teaching most directly addresses him?', '["Whoever fasts Ramadan with iman and hope of reward has his past sins forgiven","Allah has no need of one who leaves food and drink yet does not leave false speech and acting upon it","The fasting person has two joys: one at breaking fast and one when meeting his Lord","Fasting and the Quran will intercede for the servant on the Day of Resurrection"]'::jsonb, 1, 'Sahih al-Bukhari #1903: a fast that abstains from food while persisting in falsehood misses its purpose, because the goal is taqwa, not hunger. The other narrations are authentic virtues of fasting, but none of them confronts the separation of ritual from conduct — which is this man''s exact error.', 'sawm', 'application');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-fp-11', 'quiz-five-pillars', 'Hajj is obligatory upon a Muslim how often, and under what condition?', '["Every year, for whoever owns wealth above the nisab threshold","Once every ten years, following the practice of the Companions after the Prophet''s ﷺ death","Once in a lifetime, upon the one who has the ability — in body, wealth and route","Twice in a lifetime, once for oneself and once on behalf of one''s parents"]'::jsonb, 2, '“And due to Allah from the people is pilgrimage to the House — for whoever is able to find a way to it” (Aal Imran 3:97), and the Prophet ﷺ clarified that it is once; whatever is extra is voluntary. The condition of ability (istita''ah) covers physical capacity, sufficient wealth, and a safe route. Hajj on behalf of parents exists as a voluntary act after one''s own, but is not a second obligation.', 'hajj', 'recall');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-fp-12', 'quiz-five-pillars', 'What did the Prophet ﷺ promise the one who performs hajj without obscenity or transgression?', '["He returns free of sin, as on the day his mother bore him","He is guaranteed that his next forty years of supplications will be answered","He receives the reward of a martyr who died defending the sacred places","He and seventy of his relatives are granted intercession on the Day of Judgment"]'::jsonb, 0, 'Sahih al-Bukhari #1521: “...returns as on the day his mother bore him.” The distractors borrow the *style* of virtue-narrations but attach unverified specifics — a useful habit to build: when you hear a precise-sounding reward, ask for the source. The authentic promise is total erasure of sins, conditioned on avoiding rafath (obscenity) and fusuq (transgression) during the rites.', 'hajj', 'application');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-fp-13', 'quiz-five-pillars', 'Why do the scholars say the five pillars were ordered with the shahadatayn first, rather than beginning with the prayer?', '["Because the testimony takes the least time to perform, and the religion moves from lighter to heavier duties","Because the other four pillars were revealed later in Madinah, long after the testimony","Because a person cannot be judged in Islamic courts until he has publicly pronounced the testimony","Because every outward deed depends for its acceptance on the belief the testimony expresses"]'::jsonb, 3, 'The pillars are ordered by dependency: worship without tawheed is a structure with no foundation, so the shahadah is the condition for everything after it. The chronology option is partly factual for zakah and hajj but fails as the *reason* — prayer was obligated in Makkah, yet still comes after the testimony in every listing. Order here teaches priority, not history.', 'pillars-general', 'analysis');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-fp-14', 'quiz-five-pillars', 'A new Muslim asks: “If I struggle to fast for medical reasons, does that break my Islam, since fasting is a pillar?” What is the sound answer?', '["Yes — a structure with a missing pillar collapses, so all five must be performed by everyone","No — the Shariah itself excuses the sick and legislates alternatives, which is different from rejecting the pillar","Yes — but only if the illness continues for more than two consecutive Ramadans without repayment","No — because fasting is the least emphasized of the pillars and its abandonment carries no consequence"]'::jsonb, 1, 'The same Quranic passage that obligates fasting excuses the sick and traveler (al-Baqarah 2:184-185) with making up days or fidyah — using a legislated concession is obedience, not abandonment. The pillar is undermined by *denying* its obligation or abandoning it without excuse, not by availing an excuse Allah Himself revealed. The “collapse” image applies to rejection, not to concession.', 'sawm', 'application');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-fp-15', 'quiz-five-pillars', 'Which grouping correctly matches each pillar to the kind of right it primarily represents, as the scholars describe it?', '["Prayer and fasting — bodily worship; zakah — wealth; hajj — both body and wealth","Prayer and zakah — bodily worship; fasting — wealth; hajj — community solidarity","Prayer — wealth; zakah and fasting — bodily worship; hajj — purely spiritual worship","All four practical pillars are bodily acts, while wealth enters only through voluntary charity"]'::jsonb, 0, 'The classical breakdown: salah and sawm are acts of the body, zakah is the act of wealth, and hajj combines body and wealth (travel, ihram, expenditure). The point of the division is completeness — submission claims the whole person, physical and financial. It also explains rulings like appointing a hajj proxy for the physically unable but financially capable.', 'pillars-general', 'analysis');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-fp-16', 'quiz-five-pillars', 'In the hadith “Islam is built upon five,” what does the building metaphor imply about a Muslim who neglects some pillars while affirming them all?', '["His Islam is void in all cases, exactly like the one who never testified at all","The metaphor is only rhetorical and carries no implication for rulings whatsoever","His structure stands but deficient and endangered — with the prayer being the weight-bearing case the texts single out","The building refers to the community as a whole, so individual neglect affects only communal reward"]'::jsonb, 2, 'A building missing parts of its structure still stands — weakened — which is how the scholars describe the sinful neglecter who does not deny the obligation; but the texts single out the prayer with unique severity (Sahih Muslim #82). Equating every neglect with apostasy overstates the metaphor, while emptying it of meaning understates the danger. The Salaf held both: hope for the sinner, alarm for the prayer-abandoner.', 'pillars-general', 'analysis');
insert into public.quizzes (id, module_id) values ('quiz-six-pillars', 'six-pillars');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-sp-01', 'quiz-six-pillars', 'How do Ahlus Sunnah define iman?', '["Sincere conviction of the heart, which outward deeds can neither strengthen nor weaken","Verbal affirmation of the testimony witnessed by two upright Muslims","Statement of the tongue, belief of the heart, and action of the limbs — increasing with obedience and decreasing with sin","Complete knowledge of the six pillars together with the ability to cite their proofs"]'::jsonb, 2, 'This three-part definition distinguishes Ahlus Sunnah from those who reduced iman to inner conviction alone. The Prophet ﷺ counted even removing harm from the road as a branch of iman (Sahih Muslim #35), which is an action — so action enters iman''s reality, and iman rises and falls. The first option is the position of the Murji''ah, historically refuted by the imams of the Salaf.', 'iman-definition', 'recall');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-sp-02', 'quiz-six-pillars', 'A Muslim says: “My iman feels weak lately.” According to the definition of Ahlus Sunnah, what follows from this statement?', '["It reflects reality — iman genuinely increases with obedience and decreases with sin, so it can be rebuilt by action","It is a misunderstanding, since iman is constant once a person truly believes and only hypocrisy fluctuates","It signals that his original testimony was defective and should be renewed before a witness","It means his knowledge is lacking, because iman is exactly proportional to how much a person has studied"]'::jsonb, 0, 'Because action is part of iman, iman moves: “that they may increase in iman along with their iman” (al-Fath 48:4). The practical fruit is hope — weakness is treated with prayer, Quran and remembrance, not despair. The fixed-iman option is the Murji''i conception, and tying iman strictly to study confuses knowledge (a cause) with iman itself.', 'iman-definition', 'application');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-sp-03', 'quiz-six-pillars', 'Belief in Allah, as the scholars unpack it, contains four components. Which list is correct?', '["His existence, His justice, His mercy, and His wisdom","His existence, His prophets, His books, and His decree","His oneness in creating, His oneness in sustaining, His oneness in judging, and His oneness in reviving the dead","His existence, His rububiyyah, His uluhiyyah, and His names and attributes"]'::jsonb, 3, 'Belief in Allah = believing He exists, that He alone is Lord (creates, owns, governs), that He alone deserves worship, and that His names and attributes are as He revealed them. The third option lists only fragments of rububiyyah, making it the tempting near-miss. This four-part outline becomes the full Categories of Tawheed module later in the curriculum.', 'belief-in-allah', 'recall');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-sp-04', 'quiz-six-pillars', 'Which of the following correctly describes the angels according to the Quran and Sunnah?', '["Forces of nature that the early generations personified in order to teach simple people","Created servants made from light who never disobey Allah''s command","Daughters of Allah who intercede for mankind, as some earlier nations held","Spirits of the righteous dead elevated to carry out Allah''s commands"]'::jsonb, 1, '“Created from light” is stated in Sahih Muslim #2996, and their sinlessness in at-Tahrim 66:6 — “they do not disobey Allah in what He commands them.” The “daughters of Allah” claim is the pagan belief the Quran refutes directly (an-Najm 53:27), and reading angels as metaphors for nature is a modernist reinterpretation that empties a pillar of iman of its content.', 'angels', 'recall');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-sp-05', 'quiz-six-pillars', 'What is the intended practical effect of believing that two recording angels accompany every person?', '["Watchfulness over one''s words and deeds, since nothing said escapes the record","Fear of angels themselves, since they are given authority to punish sins as they occur","Comfort that minor sins are erased automatically before they reach the record","Certainty that one''s destiny changes each time the record is reviewed in the heavens"]'::jsonb, 0, '“Not a word does he utter except that with him is an observer prepared” (Qaf 50:18) — the fruit is muraqabah, self-watchfulness. The angels record; judgment belongs to Allah alone, so fearing *them* misplaces the matter. This is a recurring pattern in aqeedah: every article of belief is meant to produce a state in the heart and a change in behaviour.', 'angels', 'application');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-sp-06', 'quiz-six-pillars', 'A Muslim reads Bible passages and asks how to regard the earlier scriptures. What is the position taught by belief in Allah''s books?', '["Earlier scriptures should be treated exactly like the Quran since one Author revealed them all","Earlier scriptures are entirely fabricated by men and no true revelation ever existed among their people","Nothing may be affirmed or denied of any earlier scripture until specialists authenticate each verse","Allah truly revealed books before the Quran, but their current texts were altered, and the Quran now stands as criterion over them"]'::jsonb, 3, 'We believe in the original Tawrah, Zabur and Injil as true revelation, and that their peoples altered them (al-Baqarah 2:79), while the Quran is guarded (al-Hijr 15:9) and made a muhaymin — criterion — over what preceded it (al-Ma''idah 5:48). So current texts are judged by the Quran: what agrees is accepted, what contradicts is rejected. Denying the original revelations altogether rejects a pillar of iman just as surely as equating them with the Quran.', 'books', 'application');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-sp-07', 'quiz-six-pillars', '“We did not send any messenger before you except that We revealed to him: none has the right to be worshipped except Me, so worship Me” (al-Anbiya 21:25). What does this ayah establish about the messengers?', '["Each messenger brought a different conception of God suited to his people''s culture","Their core message was one — tawheed — even as their revealed laws differed","Only the messengers mentioned by name in the Quran called to tawheed","The messengers taught lordship of Allah while leaving forms of worship to local custom"]'::jsonb, 1, 'One creed, many codes: every messenger from Nuh to Muhammad ﷺ called to worshipping Allah alone, while the practical shariah varied between nations. This matters for da''wah: Islam does not present itself as a new religion but as the original religion of all the prophets. The last option smuggles in exactly what the messengers came to abolish — humanly devised worship.', 'messengers', 'application');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-sp-08', 'quiz-six-pillars', 'Someone claims to be a “final spiritual teacher” receiving revelation for our age. Which text most directly rules on this claim?', '["“And We certainly sent into every nation a messenger” (an-Nahl 16:36)","“This day I have perfected for you your religion” (al-Ma''idah 5:3)","“Muhammad is not the father of any of your men, but the Messenger of Allah and the seal of the prophets” (al-Ahzab 33:40)","“Say: if you love Allah, then follow me; Allah will love you” (Aal Imran 3:31)"]'::jsonb, 2, '“Seal of the prophets” closes prophethood itself; the Prophet ﷺ added, “there is no prophet after me” (al-Bukhari #3455). Al-Ma''idah 5:3 is the strongest *supporting* proof — a perfected religion needs no new revelation — which makes it the tempting distractor, but the direct ruling on claimed prophethood is the seal-ayah. Every claimant after Muhammad ﷺ is, by text, false.', 'messengers', 'analysis');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-sp-09', 'quiz-six-pillars', 'Which of the following is included in belief in the Last Day, before the Resurrection itself?', '["The return of the soul to a second worldly life to complete unfinished deeds","The sleeping of every soul until the Horn, with no awareness in the grave whatsoever","The immediate entry of all believers into Paradise at the moment of death","The trial of the grave — its questioning, and its bliss or punishment"]'::jsonb, 3, 'The Last Day encompasses everything the texts report after death: the grave''s questioning (the three questions studied in Usul al-Thalathah), its bliss or torment, then Resurrection, records, scale, sirat, and the final abodes. Reincarnation contradicts the Quran''s finality of death (al-Mu''minun 23:99-100), and the grave is described as aware — “a garden from the gardens of Paradise or a pit from the pits of Fire.”', 'last-day', 'recall');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-sp-10', 'quiz-six-pillars', '“So whoever does an atom''s weight of good will see it, and whoever does an atom''s weight of evil will see it” (az-Zalzalah 99:7-8). What behavioural effect is this ayah designed to produce?', '["Anxiety so constant that a believer never feels secure about any deed he has done","Precision of conscience — no deed is too small to matter, in private or public","Focus on major deeds only, since small ones balance each other out in the scale","Confidence that good intentions outweigh actions regardless of what one actually does"]'::jsonb, 1, 'The ayah installs an audit down to the atom''s weight, which is why belief in the Last Day is the engine of Islamic ethics: the one certain of the accounting watches himself in the dark. The intended state is watchfulness paired with hope — not paralyzing anxiety, which the Quran counters with Allah''s mercy and acceptance of repentance. Dismissing small deeds directly contradicts the text.', 'last-day', 'application');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-sp-11', 'quiz-six-pillars', 'The scholars summarize belief in al-qadar with four levels. Which list is correct?', '["Allah''s knowledge, His writing of all things, His will, and His creation of all that occurs","Allah''s justice, His mercy, His wisdom, and His power over all things","Human intention, human effort, divine assistance, and divine acceptance","The Preserved Tablet, the pens of the angels, the scrolls of deeds, and the final scale"]'::jsonb, 0, 'The four levels: al-''ilm (He knows all things), al-kitabah (He wrote them — Sahih Muslim #2653: fifty thousand years before creation), al-mashi''ah (nothing occurs except by His will), and al-khalq (He is Creator of everything, az-Zumar 39:62). The last option lists real items of the unseen but not the levels of qadar — a classic near-miss for those who memorized labels without structure.', 'qadar', 'recall');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-sp-12', 'quiz-six-pillars', 'After losing a job he worked hard to keep, a Muslim says: “I did what I could — this was written, and Allah will provide otherwise.” How does this response embody correct belief in qadar?', '["It doesn''t — accepting decree means he should not have exerted effort to keep the job in the first place","It is deficient, because the decree only concerns acts of worship and has nothing to do with worldly provision","It joins taking the means with rest of heart upon the outcome — effort first, then acceptance of what was written","It is acceptable only if he can identify the specific sin for which the loss was a punishment"]'::jsonb, 2, 'Belief in qadar governs the *aftermath* of effort, not a substitute for it: “so that you not despair over what has escaped you” (al-Hadid 57:22-23). The Prophet ﷺ commanded tying the camel and trusting in Allah — means and reliance together. Fatalism (abandoning means) and restricting decree to rituals are both errors; and calamity is not automatically traceable to a specific sin.', 'qadar', 'application');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-sp-13', 'quiz-six-pillars', 'A man excuses his sin by saying: “Allah decreed it for me, so how can I be blamed?” What is the classical response of Ahlus Sunnah?', '["He is right in principle, but blame attaches anyway as a deterrent for others","Decree is Allah''s hidden knowledge, not the criterion of action — he chose and acted willingly, and is judged by the command, not by the decree he never saw","He is right, which is why punishments in Islam apply only to those who sin openly and boastfully","Decree covers only good deeds, while evil deeds fall entirely outside what Allah has written"]'::jsonb, 1, 'No one knows the decree before it happens, so it cannot function as a guide or excuse; the sinner followed his own desire, not a revealed text. The scholars also note the argument''s inconsistency: the same man never accepts “it was decreed” from someone who wrongs *him*. Saying evil falls outside the writing is the error of the early Qadariyyah, refuted by “all things We created with a decree” (al-Qamar 54:49).', 'qadar', 'analysis');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-sp-14', 'quiz-six-pillars', 'Why does the Quran so often pair “belief in Allah” with “the Last Day” specifically, out of all six pillars?', '["Because the two together frame all conduct — the One watching, and the Day of accounting before Him","Because the remaining four pillars were revealed later in the Madinan period","Because belief in the Last Day was the only pillar the Arabs of Makkah already accepted","Because the angels, books and messengers are included within belief in the Last Day"]'::jsonb, 0, 'Beginning and end: the Source of the command and the Day of its audit bracket every deed between them, so the pair stands in for the whole of religion''s seriousness. Makkah''s pagans in fact *mocked* resurrection (“who will give life to bones when they are dust?” — Ya-Sin 36:78), which reverses the third option. The pillars were taught together from the beginning, as the hadith of Jibreel shows.', 'last-day', 'analysis');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-sp-15', 'quiz-six-pillars', 'The Prophet ﷺ said iman has seventy-odd branches, “the highest is la ilaha illa Allah and the lowest is removing harm from the road.” What does this hadith establish about iman?', '["That iman''s branches are all equal, so neglecting any one of them equals neglecting the testimony itself","That the branches beyond the testimony are optional refinements for those seeking extra reward","That modesty, being mentioned separately, stands outside iman as its own category","That iman spans ranked levels from creed to conduct, including deeds as ordinary as clearing a path"]'::jsonb, 3, 'The hadith (Sahih Muslim #35) builds a hierarchy — branches, highest and lowest — placing both the kalimah and street-level kindness inside iman''s single structure. That refutes both flattening (all branches equal) and exclusion (deeds outside iman). Modesty (haya) is named as “a branch *of* iman,” inside the structure, not beside it.', 'iman-definition', 'application');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-sp-16', 'quiz-six-pillars', 'A da''wah leaflet lists the pillars of iman as: Allah, the angels, the books, the messengers, and the Last Day — five items. What should be corrected, and why does it matter?', '["Nothing — the sixth item, ihsan, belongs to a different hadith and is often merged by mistake","Add belief in al-qadar — its good and its bad — for the hadith of Jibreel names it as the sixth pillar","Replace “the books” with “the Quran,” since belief in altered scriptures is no longer required","Add belief in the Companions, since rejecting them was the first deviation in the ummah"]'::jsonb, 1, 'The hadith of Jibreel ends the list: “...and that you believe in al-qadar, its good and its bad” (Sahih Muslim #8) — precisely the pillar most often dropped, and historically the first to be denied by a sect. Ihsan is indeed in the same hadith but as a separate level of the religion, not a pillar of iman — making the first option the studied-sounding trap. Respect for the Companions is obligatory but is not one of the six.', 'iman-definition', 'application');
insert into public.quizzes (id, module_id) values ('quiz-usul-al-thalathah', 'usul-al-thalathah');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-ut-01', 'quiz-usul-al-thalathah', 'The author opens Thalathat al-Usul with four matters obligatory on every Muslim. Which list is correct?', '["Knowledge, action upon it, inviting to it, and patience upon the harm encountered","Prayer, fasting, charity, and pilgrimage as the practical core of the religion","Sincerity, truthfulness, humility, and constant remembrance of Allah","Reading the Quran, learning Arabic, memorizing the fundamentals, and finding a teacher"]'::jsonb, 0, 'Knowledge → action → da''wah → patience: the sequence of Surah al-''Asr, which the author cites as proof, and about which ash-Shafi''i said that had nothing else been revealed it would have sufficed the creation. The other lists contain genuine virtues, but the four matters map the *lifecycle* of knowledge — acquiring it, living it, spreading it, and bearing its cost.', 'four-matters', 'recall');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-ut-02', 'quiz-usul-al-thalathah', 'Imam al-Bukhari titled a chapter “Knowledge comes before speech and action,” citing Surah Muhammad 47:19. What in the ayah''s wording supports this order?', '["It addresses the Prophet ﷺ, whose knowledge preceded the whole ummah''s practice","The command “know” (that none deserves worship except Allah) comes before the command to seek forgiveness","It was revealed in Makkah before any acts of worship were legislated for the believers","The word “knowledge” appears in it more often than the word “action” appears"]'::jsonb, 1, 'The ayah''s structure — fa''lam (know!) then wastaghfir (seek forgiveness) — puts knowledge textually before the act of worship, and al-Bukhari drew the principle from that ordering. The point is methodological: worship performed ignorantly goes wrong in belief or form. The Makkan-revelation claim is historically confused and, either way, wouldn''t establish the ordering the chapter title asserts.', 'four-matters', 'analysis');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-ut-03', 'quiz-usul-al-thalathah', 'Why does patience (sabr) belong in a list about knowledge and da''wah at all?', '["Because patience is the most virtuous act in Islam, so every list must include it","Because acquiring knowledge requires patience with long study hours and difficult texts","Because the one who calls to truth will be opposed, and without patience he abandons the path","Because patience compensates for whatever knowledge or action a person happens to lack"]'::jsonb, 2, 'The four matters form a chain, and the last link answers the cost of the third: whoever invites to what he knows and practices *will* meet harm — every prophet did. Surah al-''Asr''s ending (“counsel one another to patience”) sits exactly where the resistance begins. Patience in study (option two) is real but secondary; the author''s own proof-text ties sabr to the mutual counseling of truth.', 'four-matters', 'application');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-ut-04', 'quiz-usul-al-thalathah', 'Asked “Who is your Lord?”, the matn''s answer is: “My Lord is Allah, who nurtured me and all the worlds with His blessings.” How does the author say a person comes to *know* this Lord?', '["Through inherited belief passed down reliably from one''s parents and community","Through the direct witnessing of the heart once it has been purified by worship","Through the rational proofs developed by the scholars of theology (kalam)","Through His signs — like the night, day, sun and moon — and His creations"]'::jsonb, 3, 'The matn answers explicitly: “I know Him by His signs and His creations,” citing Fussilat 41:37 and al-A''raf 7:54. Reflection on creation is the Quran''s own repeated method — accessible to every person, unlike kalam''s imported syllogisms which the Salaf censured. Inherited belief describes how many people *hold* the answer, but the grave''s question demands knowledge, not inheritance.', 'knowing-lord', 'recall');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-ut-05', 'quiz-usul-al-thalathah', 'Fussilat 41:37 commands: “Do not prostrate to the sun or the moon, but prostrate to Allah who created them.” In the context of knowing your Lord, what principle is this ayah teaching?', '["That astronomy is a discouraged science because it draws hearts toward the celestial bodies","That the signs of creation must lead past themselves to their Maker, never becoming objects of veneration","That prostration in Islam is reserved for the direction of the Ka''bah alone","That the sun and moon possess no benefit for mankind and deserve no attention"]'::jsonb, 1, 'The very things listed as signs pointing *to* Allah — sun and moon — are forbidden as objects of worship, closing the gap where nations before slipped from admiring creation into venerating it. Signs are arrows, not destinations. The ayah presupposes the sun and moon are magnificent and beneficial; that is exactly why the warning is needed.', 'knowing-lord', 'application');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-ut-06', 'quiz-usul-al-thalathah', 'The matn moves from “He nurtured all the worlds” directly to “He is my object of worship.” A reader asks: why does lordship *obligate* worship? Which reasoning matches the Quran''s?', '["The One who created, provides and sustains is alone entitled to the gratitude and servitude of the sustained — “worship your Lord who created you” (al-Baqarah 2:21)","Since Allah is powerful, human beings worship Him primarily out of fear of punishment","Worship is mankind''s repayment of the debt of creation, and once repaid the obligation ceases","Because worship benefits Allah, and He deserves benefit from what He made"]'::jsonb, 0, 'Al-Baqarah 2:21 makes creation and provision the *reason clause* for the command to worship: rububiyyah is the premise, uluhiyyah the necessary conclusion. Worship cannot repay or benefit Allah — “I do not want from them any provision” (adh-Dhariyat 51:57) — He is worshipped because He alone deserves it. Fear is one wing of worship, but the Quran pairs it always with love and hope.', 'knowing-lord', 'analysis');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-ut-07', 'quiz-usul-al-thalathah', 'The matn defines Islam in three parts. Which option states them correctly?', '["Believing in Allah, performing the five pillars, and avoiding the seven destructive sins","Testifying, praying, and giving zakah — the three acts named first in the hadith of Jibreel","Loving Allah, fearing Allah, and placing hope in Allah in equal measure","Submitting to Allah with tawheed, yielding to Him with obedience, and freeing oneself from shirk and its people"]'::jsonb, 3, 'Istislam (submission) with tawheed, inqiyad (compliance) with obedience, and bara''ah (disavowal) from shirk and its people — each clause excludes a false claimant: the proud submitter without tawheed, the believer without practice, and the one who wants tawheed while never parting from shirk. Love, fear and hope (option three) describe the inner engines of worship, not the definition of Islam.', 'knowing-religion', 'recall');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-ut-08', 'quiz-usul-al-thalathah', 'Which statement correctly relates the three levels of the religion — Islam, Iman, Ihsan?', '["They are three names for the same reality, used interchangeably in the texts","Islam concerns outward submission, Iman the inner pillars, and Ihsan the summit — worshipping as though you see Him","Islam is for common people, Iman for students of knowledge, and Ihsan for the prophets alone","Iman precedes Islam, since the heart must believe before the limbs act"]'::jsonb, 1, 'The hadith of Jibreel defines each separately and the scholars arranged them as ascending levels: every muhsin is a believer and every believer a Muslim, but not the reverse. Ihsan — “that you worship Allah as though you see Him, and if you do not see Him, He sees you” (Muslim #8) — is attainable by any sincere servant, not reserved for prophets. When mentioned together the terms differ; only when mentioned separately can each cover the whole religion.', 'levels-of-religion', 'application');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-ut-09', 'quiz-usul-al-thalathah', 'A Muslim prays flawlessly in the mosque but carelessly when alone at home. Which level of the religion is he specifically weak in, and why?', '["Ihsan — because worship “as though you see Him” does not change when the audience does","Islam — because his outward acts are defective in their pillars and conditions","Iman — because his belief in the angels who record deeds is deficient","None — variation between public and private worship is natural and carries no meaning"]'::jsonb, 0, 'The definition of ihsan targets exactly this gap: the one aware that Allah sees him prays the same in both settings, for the Watcher never leaves. His outward acts are sound (so not Islam), and the flaw isn''t a specific denied belief (so not Iman as such) — it is the weakness of muraqabah, awareness of being seen. The hadith''s second clause — “if you do not see Him, He sees you” — is the cure.', 'levels-of-religion', 'application');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-ut-10', 'quiz-usul-al-thalathah', 'How many years did the Prophet ﷺ live, and how are they divided around the revelation?', '["Sixty years: thirty before prophethood and thirty as a prophet in Makkah and Madinah","Seventy years: fifty before prophethood, ten in Makkah and ten in Madinah","Sixty-five years: forty-five before prophethood and twenty after it began","Sixty-three years: forty before prophethood, thirteen calling in Makkah and ten in Madinah"]'::jsonb, 3, 'He ﷺ received prophethood at forty, called in Makkah thirteen years, and spent ten in Madinah after the hijrah — sixty-three in all. The matn includes this because knowing your Prophet is the third fundamental: his life is not trivia but the map of how the religion descended. The Makkan/Madinan split matters for the next question''s principle.', 'knowing-prophet', 'recall');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-ut-11', 'quiz-usul-al-thalathah', 'For thirteen Makkan years the Prophet ﷺ called almost exclusively to tawheed and warning against shirk, before most laws were revealed. What manhaj lesson do the scholars draw from this for teaching Islam today?', '["New Muslims should not be taught any fiqh until they have studied aqeedah for over a decade","Creed is rectified before rules — priorities in teaching follow the order of revelation","The Makkan period shows that rulings may be postponed indefinitely when society is hostile","Da''wah should avoid mentioning laws entirely, since laws repel people from the religion"]'::jsonb, 1, 'The order of revelation is understood as pedagogical wisdom: hearts grounded in tawheed received the laws willingly when they came — as Aisha (رضي الله عنها) observed about the verses of prohibition (al-Bukhari #4993). The lesson is *priority*, not a literal thirteen-year quarantine from fiqh; a new Muslim learns to pray immediately, while the center of gravity stays on creed. This is why the aqeedah department anchors this curriculum.', 'knowing-prophet', 'analysis');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-ut-12', 'quiz-usul-al-thalathah', 'With which revelation did the Prophet''s ﷺ *messengership* (being sent to warn) begin, according to the matn?', '["Surah al-Fatiha, since it is the mother of the Book and the first complete surah","Ayat al-Kursi, since it is the greatest single ayah in the Quran","“O you wrapped in a cloak: arise and warn” — Surah al-Muddaththir","“Read in the name of your Lord who created” — Surah al-''Alaq"]'::jsonb, 2, 'The scholars distinguish: with Iqra (al-''Alaq) he became a *prophet* (received revelation); with al-Muddaththir — “arise and warn” — he was *sent* as a messenger with a mission to others. Al-''Alaq is the tempting answer because it came first, but it contained no commission to call anyone. The matn is precise: nubuwwah with Iqra, risalah with al-Muddaththir.', 'knowing-prophet', 'application');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-ut-13', 'quiz-usul-al-thalathah', '“And We have not sent you except to all of mankind” (Saba 34:28). A person argues Islam was meant for the Arabs of that time and place. Beyond this ayah, which fact of the Prophet''s ﷺ own practice most directly refutes him?', '["He ﷺ retained Arabic as the language of prayer for all peoples entering Islam","He ﷺ commanded that his sayings be memorized with their exact chains of narration","He ﷺ performed hajj with over one hundred thousand Muslims of many tribes","He ﷺ sent letters inviting the rulers of Rome, Persia and Abyssinia to Islam"]'::jsonb, 3, 'The letters to Heraclius, Chosroes and the Negus (Sahih al-Bukhari #7 records the letter to Heraclius) are the Prophet''s ﷺ own application of a universal message — non-Arab empires, invited by name. The other options are true practices but show internal matters of the community, not the outward claim over all nations. Method: refute claims about the message with the Messenger''s ﷺ own conduct.', 'knowing-prophet', 'analysis');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-ut-14', 'quiz-usul-al-thalathah', 'The three questions of the grave are: Who is your Lord? What is your religion? Who is your prophet? According to the texts, what determines a person''s ability to answer them?', '["Memorizing the answers in Arabic during one''s lifetime exactly as worded in the matn","The firmness Allah gives to those who lived upon iman — “Allah keeps firm those who believe with the firm word” (Ibrahim 14:27)","The prompting of the two angels, who assist the deceased through the questioning","One''s family reciting the answers over the grave during the burial"]'::jsonb, 1, 'The scholars of tafsir report that Ibrahim 14:27 was revealed about the questioning of the grave (al-Bukhari #4699): the answer flows from the life lived, not from rote memorization at the end. This is the entire rationale of Thalathat al-Usul — learn, believe and live these answers now. The hypocrite in the narrations says “I heard people saying something, so I said it” — memorization without iman fails the test.', 'knowing-religion', 'application');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-ut-15', 'quiz-usul-al-thalathah', 'Which pairing correctly matches each fundamental with the module of this curriculum that expands it?', '["Knowing the Lord → Fiqh of worship; knowing the religion → Hadith sciences; knowing the Prophet → Arabic","All three fundamentals are expanded only within refutations of the sects","Knowing the Lord → Categories of Tawheed; knowing the religion → the pillars of Islam and Iman; knowing the Prophet ﷺ → his seerah and Sunnah","Knowing the Lord → Names and Attributes only; the other two have no expansion in study"]'::jsonb, 2, 'The three fundamentals are a seed-map of the sacred sciences: the first unfolds into tawheed''s categories, the second into the levels and pillars you studied in the first two modules, the third into seerah and Sunnah. Seeing the curriculum this way turns a short matn into a lifetime''s syllabus — which is how the scholars actually use it with students.', 'knowing-religion', 'application');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-ut-16', 'quiz-usul-al-thalathah', 'What did Imam ash-Shafi''i say would suffice as proof upon the creation, according to the matn''s introduction?', '["Surah al-''Asr, had Allah revealed nothing else","Surah al-Ikhlas, since it equals a third of the Quran in meaning","Ayat al-Kursi, since it gathers the names and attributes of Allah","Surah al-Fatiha, since no prayer is valid without it"]'::jsonb, 0, 'The statement — “had Allah sent down only this surah as proof upon His creation, it would have sufficed them” — refers to al-''Asr, because its three ayat contain the complete program: iman, action, mutual counsel to truth, and patience. The virtues in the other options are all authentic but answer different questions; this one is about a *sufficient proof for the human obligation*.', 'four-matters', 'recall');
insert into public.quizzes (id, module_id) values ('quiz-categories-of-tawheed', 'categories-of-tawheed');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-ct-01', 'quiz-categories-of-tawheed', 'Which action belongs to Tawheed ar-Rububiyyah — Allah''s oneness in His own actions?', '["Mankind''s directing of all supplication to Allah alone","Allah''s giving of life and death and His management of every affair","The believer''s affirmation of Allah''s names as revealed in the Quran","The pilgrim''s sacrifice being offered exclusively for Allah"]'::jsonb, 1, 'Rububiyyah concerns what *Allah does* — creating, providing, giving life and death, governing (az-Zumar 39:62). Uluhiyyah concerns what *servants do* toward Him (du''a, sacrifice), and asma wa sifat concerns what we *affirm about* Him. Sorting any statement into “His actions / our actions / His descriptions” is the fastest way to classify it correctly.', 'rububiyyah', 'recall');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-ct-02', 'quiz-categories-of-tawheed', 'The Quran records that the Makkan pagans, when asked who created them, “would surely say: Allah” (az-Zukhruf 43:87). What do the scholars conclude from this?', '["The pagans were secretly Muslims whose social pressure prevented open practice","The Quran describes only a small educated elite among them, not the masses","Affirming Allah as Creator, alone, did not enter them into Islam — the dispute was over worship","The ayah abrogated earlier verses that had described them as deniers of the Creator"]'::jsonb, 2, 'This is the most consequential conclusion in the whole subject: rububiyyah-affirmation is near-universal and has never by itself made anyone a Muslim, for the messengers were sent over the issue of *whom to worship*. It refutes the assumption that shirk means denying God''s existence. The Quran calls those same affirmers mushrikun because their du''a, sacrifice and hope went to others.', 'rububiyyah', 'application');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-ct-03', 'quiz-categories-of-tawheed', 'Why does the Quran repeatedly argue from rububiyyah (“who provides for you?”) when its actual demand is uluhiyyah (worship Him alone)?', '["Because the premise they already accepted logically obligates the worship they refused","Because rububiyyah was the point they denied, so the Quran concentrates its proofs there","Because worship cannot be commanded until people first master theology","Because provision is the greatest of Allah''s blessings and gratitude is its price"]'::jsonb, 0, 'The Quran''s method is argument from the conceded to the disputed: you admit He alone creates and provides (conceded) — then how do you worship what creates nothing (an-Nahl 16:17)? Option two reverses the facts: rububiyyah was *accepted*, uluhiyyah refused. Recognizing this method equips you to answer the modern claim that “believing in God” suffices.', 'rububiyyah', 'analysis');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-ct-04', 'quiz-categories-of-tawheed', 'Ibn Taymiyyah defined ''ibadah (worship) as:', '["The five pillars performed with sincerity and following the Sunnah","Everything commanded in the Quran as understood by the four schools of law","The heart''s humility before Allah accompanied by hope in His reward","A comprehensive term for all that Allah loves and is pleased with, of statements and actions, inward and outward"]'::jsonb, 3, 'This definition (from al-''Ubudiyyah) is deliberately wide: it captures du''a, fear, hope, reliance, sacrifice, and even ordinary acts ennobled by intention. Its width is what makes shirk detectable — if du''a is worship, then du''a to the dead is worship given to creation. The narrower options each miss categories (inward acts, statements) that the texts treat as worship.', 'uluhiyyah', 'recall');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-ct-05', 'quiz-categories-of-tawheed', 'A man at a shrine says: “I know the saint cannot create or provide — only Allah does that. I simply call on him to relay my need to Allah.” Classify his statement.', '["Sound tawheed, since he correctly attributes creation and provision to Allah alone","Correct rububiyyah with a violation of uluhiyyah — du''a is worship, and he has directed it to other than Allah","A minor error of etiquette in supplication, provided his intention remains directed at Allah","An error of asma wa sifat, since he has denied Allah''s attribute of hearing"]'::jsonb, 1, 'His creed about creation is intact; his *practice* gives the worship of du''a to a creature — precisely the split the Quran describes in Yunus 10:18 (“these are our intercessors with Allah”). The Prophet ﷺ said “du''a is worship” (authentic, at-Tirmidhi #2969), so redirecting it is not etiquette but shirk in uluhiyyah. This scenario is the second principle of al-Qawa''id al-Arba'' in modern clothes.', 'uluhiyyah', 'application');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-ct-06', 'quiz-categories-of-tawheed', 'In the hadith of Mu''adh, the Prophet ﷺ said the right of Allah upon His servants is:', '["That they thank Him for every blessing and endure every trial without complaint","That they seek knowledge of Him through study before performing any deed","That they worship Him and do not associate anything with Him","That they establish prayer, give zakah, and treat creation with excellence"]'::jsonb, 2, 'Al-Bukhari #2856, Muslim #30 — the first right of all rights, stated in a single clause joining affirmation (worship Him) and negation (no partners). The pairing matters: worship of Allah *plus* worship of others fulfils neither half. The other options list real duties, but the hadith names the root from which they all branch.', 'uluhiyyah', 'recall');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-ct-07', 'quiz-categories-of-tawheed', '“You alone we worship, and You alone we ask for help” (al-Fatiha 1:5). How do the scholars relate this ayah''s two halves to the categories of tawheed?', '["Worship expresses uluhiyyah; seeking help expresses reliance on the Lord who alone controls all things","Both halves express rububiyyah, since prayer and help both come from the Lord","Worship refers to the pillars of Islam while help refers to the pillars of iman","The first half abrogates the second, indicating worship suffices without supplication"]'::jsonb, 0, '“You alone we worship” is the servant''s tawheed al-uluhiyyah; “You alone we ask for help” flows from tawheed ar-rububiyyah — only the One who governs everything can be relied upon absolutely. The ayah thus binds the two categories in one line recited in every rak''ah. The scholars note the order too: worship (His right) precedes asking (our need).', 'uluhiyyah', 'analysis');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-ct-08', 'quiz-categories-of-tawheed', 'State the manhaj of Ahlus Sunnah toward the ayat and ahadith of Allah''s attributes.', '["Affirm them as they came, in a manner befitting His majesty — without distortion, denial, asking how, or likening","Reinterpret them metaphorically so that they conform to what reason judges possible for God","Pass their wording on without affirming any meaning, since their meaning is unknowable","Affirm those attributes reason can verify and suspend judgment on the remainder"]'::jsonb, 0, 'The rule stands on ash-Shura 42:11 — “There is nothing like Him” (refuting tamthil/takyif) “and He is the Hearing, the Seeing” (refuting ta''til/tahrif). The meanings are known in Arabic; the *how* is what''s beyond us — as Malik said of the istiwa: “the rising is known, the how is unknown.” Option three (tafwid of meaning) sounds pious but implies the Quran addresses hearts with unintelligible words.', 'asma-wa-sifat', 'recall');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-ct-09', 'quiz-categories-of-tawheed', 'Someone reads “the Hand of Allah is over their hands” (al-Fath 48:10) and says: “This must mean His power, because a real hand would make Him resemble creation.” What is the flaw in his reasoning?', '["Nothing — this is precisely how the Companions dealt with such texts","He assumed affirming an attribute implies resemblance, when Allah''s attributes befit Him just as His essence is unlike ours","His error is quoting an ayah without first mastering the science of abrogation","He is right about the hand but wrong to reason about attributes at all"]'::jsonb, 1, 'The hidden premise — “a real attribute entails creaturely likeness” — is the root error of the negators: it treats resemblance as automatic, when Allah affirmed for Himself hearing and seeing while nothing is like Him (ash-Shura 42:11). We affirm a Hand befitting His majesty, unlike ours, without asking how. The Companions affirmed such texts without reinterpretation — no authentic transmission shows them converting attributes into abstractions.', 'asma-wa-sifat', 'application');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-ct-10', 'quiz-categories-of-tawheed', 'What does “enumerating” Allah''s names (man ahsaha) mean in the hadith “Allah has ninety-nine names; whoever enumerates them enters Paradise”?', '["Reciting the list of names a fixed number of times daily as dhikr","Compiling and memorizing all the names in their exact revealed sequence","Memorizing, understanding, and worshipping Allah through their meanings","Writing the names and keeping them in the home for blessing"]'::jsonb, 2, 'The scholars explain ihsa in three ascending steps: memorize the wording, understand the meaning, and act — trust ar-Razzaq when provision tightens, watch as-Sami'' before speaking (al-Bukhari #2736; Muslim #2677). No fixed sequence or count-ritual is authentically prescribed; treating the names as talismans replaces worship *through* them with superstition *about* them.', 'asma-wa-sifat', 'application');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-ct-11', 'quiz-categories-of-tawheed', 'Which of the following is MAJOR shirk — expelling its doer from Islam if he dies upon it unrepentant?', '["Swearing an oath by one''s father out of lingering habit","Improving one''s recitation when aware that people are listening","Saying “what Allah willed and you willed” to a person","Slaughtering an animal as an offering to a jinn for protection from harm"]'::jsonb, 3, 'Sacrifice is worship (“Say: my prayer, my sacrifice, my living and my dying are for Allah, Lord of the worlds” — al-An''am 6:162), so offering it to a jinn directs worship to creation: major shirk. The other three are forms of *minor* shirk the Prophet ﷺ warned about — swearing by other than Allah, riya, and equating creatures with Allah in wording (“say: what Allah willed, *then* what you willed”). Knowing the boundary protects from both carelessness and unjustified takfir.', 'shirk', 'application');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-ct-12', 'quiz-categories-of-tawheed', 'Why did the Prophet ﷺ call riya (beautifying worship for observers) “the hidden shirk” and fear it for his Companions?', '["Because it redirects the intention of worship toward people while the outward act looks perfectly sound","Because it involves publicly declaring allegiance to idols under compulsion","Because the Companions were known to abandon prayers when no one watched them","Because any deed seen by others is automatically void of reward"]'::jsonb, 0, 'Riya corrupts the unseen engine of the deed — intention — leaving nothing visible to correct, which is exactly why it is “hidden” and why the best generation was warned about it. Being *seen* doing good is not the sin; *doing it in order to be seen* is. A deed begun for Allah and witnessed incidentally keeps its reward; one performed for the audience is minor shirk that starves the deed.', 'shirk', 'analysis');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-ct-13', 'quiz-categories-of-tawheed', 'A relative wears an amulet containing unknown writings, saying “it''s just tradition — my heart relies on Allah.” What is the correct evaluation according to this module?', '["Acceptable, since intentions determine deeds and his intention is reliance on Allah","The Prophet ﷺ forbade amulets as a means of shirk; claiming inner reliance does not clean an outward practice of jahiliyyah","Acceptable only if the writings inside turn out to be verses of the Quran","A matter of pure custom with no connection to creed in either direction"]'::jsonb, 1, 'Authentic narrations condemn tying amulets (“whoever hangs an amulet has committed shirk” — Ahmad, authentic), because attaching benefit and protection to objects is the machinery of shirk regardless of verbal disclaimers. Intention does not legitimize a forbidden means — the same logic as “we only worship them for nearness” (az-Zumar 39:3). The Quranic-amulet case is genuinely differed over among the Salaf, but *unknown writings* are condemned by agreement.', 'shirk', 'application');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-ct-14', 'quiz-categories-of-tawheed', 'Which sentence correctly distinguishes the three categories of tawheed in one line each?', '["Rububiyyah: He alone deserves worship; Uluhiyyah: He alone creates; Asma wa Sifat: He alone judges","Rububiyyah: affirmed only by Muslims; Uluhiyyah: affirmed by all nations; Asma wa Sifat: affirmed by the angels","Rububiyyah: He alone acts as Lord; Uluhiyyah: He alone is worshipped; Asma wa Sifat: He alone is described with the perfect names and attributes","The categories are a later invention with no basis in the Quran''s own structure"]'::jsonb, 2, 'His actions — our worship — His names: three sentences that organize every ayah of creed in the Quran. The categorization is extracted *from* the Quran (Surah al-Fatiha contains all three), the way grammar was extracted from speech — naming what was always there, not inventing it. Option one scrambles the definitions, and option two reverses who affirmed what.', 'categories-overview', 'application');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-ct-15', 'quiz-categories-of-tawheed', '“Indeed, Allah does not forgive that partners be associated with Him, but He forgives what is less than that for whom He wills” (an-Nisa 4:48). What do the scholars clarify about this ayah''s scope?', '["It concerns the one who dies upon shirk without repentance; sincere tawbah before death is accepted even from shirk","It applies equally to the repentant and unrepentant, making shirk unforgivable in every case","It refers only to the shirk of the nations before Islam, not to anyone of this ummah","It concerns minor shirk, while major shirk is under Allah''s will to forgive"]'::jsonb, 0, 'Az-Zumar 39:53 — “do not despair of Allah''s mercy; indeed Allah forgives all sins” — is understood by the scholars to address those who *repent*, while an-Nisa 4:48 addresses the one who meets Allah still upon shirk. Otherwise no Companion who left paganism could have been forgiven. Option four inverts the categories: it is major shirk that bars forgiveness at death, while lesser sins sit under His will.', 'shirk', 'analysis');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-ct-16', 'quiz-categories-of-tawheed', 'Your study partner summarizes: “Tawheed means believing Allah is One.” Using this module, what essential correction does his summary need?', '["None — oneness of belief is the complete meaning the texts intend","It must add that oneness covers His actions, His right to all worship, and His names and attributes — belief alone without directing worship to Him alone is the very deficiency of the mushrikun","It should replace “believing” with “declaring,” since tawheed is fulfilled by pronouncing the shahadah","It should specify that tawheed concerns knowing Allah exists, which philosophy can establish without revelation"]'::jsonb, 1, '“Allah is One” as bare belief was affirmed by the pagans of Makkah in the sense of one Creator — yet the Quran names them mushrikun for their worship. Complete tawheed unifies all three categories: Lordship, worship, and names-and-attributes. Reducing it to declaration (option three) repeats the Murji''i error from the opposite direction; reducing it to existence-belief makes revelation redundant.', 'categories-overview', 'analysis');
insert into public.quizzes (id, module_id) values ('quiz-qawaid-al-arba', 'qawaid-al-arba');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-qa-01', 'quiz-qawaid-al-arba', 'The author opens al-Qawa''id al-Arba'' with a du''a naming three signs of happiness. Which is among them?', '["When given, being grateful; when tested, being patient; when sinning, seeking forgiveness","Rising for the night prayer, fasting Mondays, and giving charity in secret","Loving the scholars, avoiding the ignorant, and keeping the company of the righteous","Certainty in provision, contentment with less, and abstinence from the world"]'::jsonb, 0, 'The opening du''a asks Allah to make the reader among those who “when given are grateful, when tested are patient, and when they sin seek forgiveness — for these three are the signs of happiness.” They cover the three states no life escapes: blessing, trial, and fault. The other options list praiseworthy matters, but the question asks for the matn''s own words.', 'hanifiyyah', 'recall');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-qa-02', 'quiz-qawaid-al-arba', 'What is the “hanifiyyah, the way of Ibrahim” that the matn commands before the four principles?', '["Making pilgrimage to the House that Ibrahim built, as the peak of devotion","Worshipping Allah alone, making the religion sincerely for Him","Practicing hospitality to guests as Ibrahim did with his visitors","Migrating from the land of one''s people for the sake of the truth"]'::jsonb, 1, 'The matn defines it directly: “that you worship Allah alone, making the religion purely for Him,” citing adh-Dhariyat 51:56. Ibrahim is the father-figure of tawheed — the one who disowned every object of worship except the One who created him (az-Zukhruf 43:26-27). Hajj and hospitality are from his legacy, but hanifiyyah names the creed, not its branches.', 'hanifiyyah', 'recall');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-qa-03', 'quiz-qawaid-al-arba', 'State the First Principle of the four.', '["The mushrikun denied Allah''s existence, and the Quran''s first task was to prove a Creator","Worship is invalid without knowledge of its conditions and nullifiers","The disbelievers whom the Prophet ﷺ confronted affirmed that Allah is the Creator and Provider — and that did not enter them into Islam","Intercession belongs entirely to Allah and may not be sought from any creature"]'::jsonb, 2, 'The first principle, with its proof from Yunus 10:31: asked who provides, who controls hearing and sight, who governs — “they will say: Allah.” Its force is in the conclusion: creed about lordship, without exclusivity of worship, left them outside Islam. Option one states the popular assumption the principle exists to demolish.', 'first-principle', 'recall');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-qa-04', 'quiz-qawaid-al-arba', 'An atheist colleague and a shrine-devotee both challenge a Muslim: “Shirk is worshipping idols; nobody does that anymore.” Using the First Principle, what is the precise reply?', '["Correct — idol worship ended with the conquest of Makkah, and modern shirk is only riya","Shirk was never defined by denying the Creator or by statues as such, but by directing worship to other than Allah — which continues in every era","Incorrect — millions of statues are still venerated in the world, so literal idolatry continues","The question is moot because shirk requires a formal declaration of leaving Islam"]'::jsonb, 1, 'The Makkans affirmed the Creator (az-Zukhruf 43:87) and still fell into shirk through worship directed elsewhere — so shirk''s definition never depended on idols or atheism. Option three is factually true but concedes the wrong premise: even if every statue vanished, du''a to the dead would remain shirk. The principle relocates the battleground from “does God exist?” to “who receives your worship?”', 'first-principle', 'application');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-qa-05', 'quiz-qawaid-al-arba', 'The Second Principle records the mushrikun''s stated motive for their worship of others. What was it?', '["Fear that abandoning ancestral gods would bring drought and defeat upon their tribes","Belief that their idols had created the lands and provided the rains","Loyalty to what their forefathers practiced, with no reasoning beyond inheritance","Seeking nearness to Allah and intercession with Him through those they venerated"]'::jsonb, 3, 'Az-Zumar 39:3 — “we only worship them that they may bring us nearer to Allah” — and Yunus 10:18 — “these are our intercessors with Allah.” They pleaded *mediation*, not independent creator-idols. Ancestral imitation (option three) appears in the Quran as a separate argument they also used, but the second principle is specifically about the nearness-and-intercession excuse, because it survives today in refined language.', 'second-principle', 'recall');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-qa-06', 'quiz-qawaid-al-arba', 'How does Allah Himself rule on the “nearness” excuse at the end of az-Zumar 39:3?', '["He accepts it from the sincere among them and rejects it from the insincere","He postpones the matter — “Allah will judge between them” — and brands the claimant a liar and ingrate","He excuses those who inherited it without access to a messenger''s teaching","He distinguishes seeking nearness through the living from seeking it through the dead"]'::jsonb, 1, 'The ayah closes: “Indeed, Allah does not guide the one who is a liar and persistently ungrateful (kaffar)” — the excuse is named a lie, and the deed disbelief, in the same breath. No partial acceptance, no living/dead distinction: the act of worship itself, whatever its stated aim, belonged to Allah. This severity is why the scholars treat the intercession-excuse as the archetype of all shirk-justifications.', 'second-principle', 'application');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-qa-07', 'quiz-qawaid-al-arba', 'A man says: “I ask the righteous dead to make du''a to Allah for me — just as I''d ask a living friend to pray for me. What''s the difference?” According to this module, where does the analogy fail?', '["There is no difference; both are permissible forms of seeking du''a from a fellow believer","The living friend is more pious than the dead saint, so his du''a is more likely answered","Asking the living is lawful interaction between capable parties; calling the dead treats them as hearers and responders beyond the grave — worship the Quran calls shirk","The difference is only etiquette: the dead should be visited at their graves before being asked"]'::jsonb, 2, 'The living friend hears by ordinary means and acts by his ability; the dead hear no supplication directed at them — “if you call upon them, they do not hear your call” (Fatir 35:14) — so calling them presumes unseen hearing and power, which is the essence of ibadah given to creation. The Companions asked the living Prophet ﷺ for du''a, and after his death asked al-Abbas — the living — instead (al-Bukhari #1010). That switch is the Salaf''s own commentary on this question.', 'second-principle', 'analysis');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-qa-08', 'quiz-qawaid-al-arba', 'The Third Principle observes that the Prophet ﷺ appeared among people worshipping different things — angels, prophets, righteous people, trees, stones, the sun and the moon. What conclusion does the principle draw?', '["He ﷺ called all of them to one tawheed, distinguishing not at all between the objects of their veneration","He ﷺ prioritized correcting the worship of stones before the worship of righteous men","He ﷺ tolerated veneration of the righteous while forbidding veneration of objects","He ﷺ addressed each group with a different religion suited to its object of worship"]'::jsonb, 0, 'One call to all: the ruling attaches to the act of worship directed at other than Allah, not to the rank of the recipient. This dismantles the intuition that venerating a prophet or saint is safer than venerating a stone — if anything the texts show the reverse, for the first shirk on earth arose from exaggerating dead righteous men (al-Bukhari #4920 on the idols of Nuh''s people). Nobility of the recipient never converts worship into permissibility.', 'third-principle', 'application');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-qa-09', 'quiz-qawaid-al-arba', 'According to Ibn Abbas''s explanation in Sahih al-Bukhari, how did the idols Wadd, Suwa'', Yaghuth, Ya''uq and Nasr originate?', '["They were carved as images of the sun, moon and planets worshipped in Babylon","They were brought to the Arabs by traders from the empires of Rome and Persia","They began as memorial images of righteous men from Nuh''s people, venerated more as generations passed until they were worshipped","They were jinn who commanded the people to erect statues in their honour"]'::jsonb, 2, 'Al-Bukhari #4920: they were righteous men; when they died, Shaytan inspired their people to set up images at their gatherings “to remember them” — and when knowledge faded, the images were worshipped. The account is the module''s historical case study: shirk enters through the door of love and memory, not the door of hatred of God. It is why the Shariah cuts the means — forbidding graves as places of worship.', 'third-principle', 'recall');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-qa-10', 'quiz-qawaid-al-arba', 'State the Fourth Principle.', '["Minor shirk leads to major shirk when left uncorrected across generations","The mushrikun of the author''s time were more consistent in their shirk than the earlier ones — who at least made worship sincere in hardship, while these invoke intermediaries in ease and hardship alike","Sincerity in hardship erases whatever shirk a person practiced in times of ease","The shirk of later nations is lighter because they inherited it without choosing it"]'::jsonb, 1, 'Proof: al-Ankabut 29:65 — on the ship in terror they call Allah alone, sincerely; delivered to land, they revert. The earlier mushrikun''s crisis-sincerity shows they knew where real power lay; those who stay with intermediaries even in extremity have gone further. Option three inverts the principle into an excuse; the crisis-sincerity is a proof *against* them, not a credit.', 'fourth-principle', 'recall');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-qa-11', 'quiz-qawaid-al-arba', 'Why is the mushrikun''s sincerity during shipwreck (al-Ankabut 29:65) treated by the Quran as evidence against them rather than in their favour?', '["Because worship performed under duress is invalid in the Shariah","Because they should have called on their idols consistently if they truly believed in them","Because it proves their fitrah knew du''a belongs to Allah alone — so their shirk in ease was against their own knowledge","Because sincerity is only accepted when accompanied by the prescribed ritual actions"]'::jsonb, 2, 'When death strips pretence away, they bypass every intermediary and call the One they know can save — testimony from their own hearts that the intermediaries were decoration. Then “when He delivers them to the land, at once they associate others.” The ayah is a fitrah-argument: crisis reveals the creed underneath, and the return to shirk in comfort convicts them by their own behaviour.', 'fourth-principle', 'analysis');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-qa-12', 'quiz-qawaid-al-arba', 'A Muslim facing surgery is told by a friend: “Keep this engraved pendant of a righteous man''s name with you — people of hardship have always used them.” Applying the four principles together, what is the sound response?', '["Accept it out of courtesy but leave it outside the operating room","Refuse it: attaching hope of protection to a venerated name or object in hardship is the pattern of shirk the principles expose — turn instead to Allah with du''a and the legislated adhkar","Accept it if the engraving includes the name of Allah alongside the righteous man''s","Refuse it only if the friend explicitly says the pendant itself heals"]'::jsonb, 1, 'The scenario stacks the module''s lessons: veneration of the righteous (third principle), the “means and nearness” excuse (second), and resort to other-than-Allah precisely in hardship (fourth). The condition in option four — waiting for an explicit claim — misses that the *practice itself* is the means of shirk the Prophet ﷺ cut off when he forbade amulets. Hardship is when tawheed is proven, as the shipwreck ayah shows.', 'fourth-principle', 'application');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-qa-13', 'quiz-qawaid-al-arba', 'Which proof-text does the matn cite for the First Principle?', '["“Say: who provides for you from the heaven and the earth...? They will say: Allah” (Yunus 10:31)","“And I did not create the jinn and mankind except to worship Me” (adh-Dhariyat 51:56)","“Allah is the Creator of all things” (az-Zumar 39:62)","“And whoever seeks a religion other than Islam, it will never be accepted from him” (Aal Imran 3:85)"]'::jsonb, 0, 'Yunus 10:31 is the matn''s chosen proof because it records the mushrikun *themselves* answering “Allah” to every rububiyyah question — provision, hearing, sight, life, death, governance — making the principle undeniable from their own mouths. The other ayat are true and related (39:62 also proves rububiyyah) but are not the citation, and the question tests reading the matn itself.', 'first-principle', 'recall');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-qa-14', 'quiz-qawaid-al-arba', 'How do the Four Principles function together as a single argument?', '["They list four historical eras of shirk from Nuh''s people to the author''s time in sequence","They grade shirk from minor to major so the student can rank sins correctly","They close four escape routes in order: “I believe in the Creator,” “I only seek nearness,” “but the one I venerate is righteous,” and “my devotion is sincere when it matters”","They prove the existence of Allah through provision, hearing, sight and governance"]'::jsonb, 2, 'Read as advocacy, the matn anticipates and shuts each defence a person might raise for venerating other than Allah: creator-belief doesn''t suffice (1), nearness-intent doesn''t excuse (2), the recipient''s righteousness doesn''t transform the act (3), and part-time sincerity convicts rather than acquits (4). Seeing the architecture is what elevates the text from four facts to one irresistible argument — and why it is taught before longer works.', 'hanifiyyah', 'analysis');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-qa-15', 'quiz-qawaid-al-arba', '“And they were not commanded except to worship Allah, making the religion sincerely His, inclining to truth” (al-Bayyinah 98:5). Which word in this ayah corresponds to the “hanifiyyah” of the matn''s introduction?', '["“Commanded” (umiru) — for the hanifiyyah is the sum of all commands","“Worship” (ya''budu) — for hanifiyyah simply means worship","“Religion” (ad-din) — for hanifiyyah is another name for the religion","“Inclining to truth” (hunafa) — the same root, describing the one who turns from shirk to pure tawheed"]'::jsonb, 3, 'Hunafa is the plural of hanif — the one who inclines away from every false object of worship toward Allah alone, as Ibrahim is repeatedly described (“hanifan musliman, and he was not of the mushrikin” — Aal Imran 3:67). The matn''s opening command to follow the hanifiyyah and this ayah share the same root and the same meaning: exclusivity of devotion. Recognizing shared roots between matn and proof is a core skill of reading classical texts.', 'hanifiyyah', 'application');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-qa-16', 'quiz-qawaid-al-arba', 'Having completed the aqeedah curriculum, a student is asked what makes the Refutations department safe for him to study now, when it was locked at the start. What is the pedagogical reason?', '["Refutations require Arabic vocabulary that is only acquired after several modules of study","Doubts are safely examined only after the correct position is firmly established with its proofs — a scale must exist before things are weighed","The lock exists to measure commitment, since only serious students finish the aqeedah track","Earlier modules earn the trust of the site''s administrators before sensitive content unlocks"]'::jsonb, 1, 'The Salaf''s method: build the affirmative creed first — the categories of tawheed, the principles concerning shirk — then encounter the deviations, which are now measurable against a fixed standard. Exposing an unanchored beginner to sophisticated doubts risks the very confusion the curriculum exists to prevent; the structure follows the order of revelation itself, creed before confrontation. The lock is pedagogy, not gatekeeping for its own sake.', 'hanifiyyah', 'analysis');
insert into public.quizzes (id, module_id) values ('quiz-nawaqid-al-islam', 'nawaqid-al-islam');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-nw-01', 'quiz-nawaqid-al-islam', 'What is the primary purpose the author gives for studying the ten nullifiers of Islam?', '["To equip students to declare specific individuals and groups to be disbelievers","So a Muslim recognizes what cancels his Islam and guards himself against it","To settle historical disputes about which past sects left the religion","To provide judges with the complete legal criteria for apostasy trials"]'::jsonb, 1, 'The author frames the list as self-protection — knowing the cliff edges to stay away from them, as knowing what breaks wudu helps you preserve it. Applying takfir to specific people has conditions and barriers that belong to the scholars and courts, which is exactly the tempting misuse this chapter is not for.', 'purpose', 'recall');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-nw-02', 'quiz-nawaqid-al-islam', 'A man says: ''I keep the pendant of a saint and call on him when I''m desperate, but I still believe only Allah creates and provides.'' Which nullifier does this fall under, and why isn''t his belief in the Creator a defense?', '["The first — directing worship such as du''a to other than Allah nullifies Islam regardless of affirming Him as Creator","The tenth — turning away from the religion entirely without learning it","None — belief that Allah alone creates and provides is sufficient to remain Muslim","The fourth — preferring another''s ruling over the ruling of the Messenger ﷺ"]'::jsonb, 0, 'Calling upon other than Allah in need is du''a directed elsewhere — the first nullifier, shirk in worship. Affirming Allah as Creator (rububiyyah) is exactly what the Makkan mushrikun did and it did not save them; the dividing line is worship, not belief in a Maker.', 'first-nullifier', 'application');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-nw-03', 'quiz-nawaqid-al-islam', 'The second nullifier concerns setting up intermediaries between oneself and Allah. Which earlier text''s argument does it directly connect to?', '["The hadith of Jibreel and its definition of ihsan","The six pillars of iman and belief in the angels","The Four Principles — that the nobility of an intermediary never makes worshipping him permissible","The five pillars of Islam and the conditions of the prayer"]'::jsonb, 2, 'The second nullifier is the practical form of what the Four Principles refuted: the mushrikun sought intermediaries for nearness and intercession, and the rank of the intermediary — angel, prophet or saint — never converts worship of him into something lawful.', 'second-nullifier', 'application');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-nw-04', 'quiz-nawaqid-al-islam', 'According to the third nullifier, what is the ruling on someone who considers the way of the mushrikun to be a valid, correct path?', '["He is excused as long as he personally practices Islam","He has himself disbelieved, for affirming la ilaha illa Allah requires negating the validity of worshipping others","His case is left entirely undecided until the Day of Judgment","He commits a major sin but remains within the fold of Islam"]'::jsonb, 1, 'The testimony negates the worship of all else and affirms it for Allah alone. To then declare that worshipping others is a valid path tears up the negation one claimed to affirm — so the third nullifier counts even doubting the mushrikun''s disbelief as disbelief.', 'third-nullifier', 'recall');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-nw-05', 'quiz-nawaqid-al-islam', 'Surah an-Nisa 4:65 — ''they will not believe until they make you judge... and submit in full submission'' — is cited for which nullifier?', '["The sixth: mocking something of the religion","The fifth: hating what the Messenger ﷺ brought","The fourth: believing another''s guidance or ruling is better than the Prophet''s ﷺ","The seventh: practicing or approving of magic"]'::jsonb, 2, 'The fourth nullifier concerns preferring another guidance or judgement over the Messenger''s ﷺ. The ayah ties iman itself to accepting his judgement without inner resistance — so believing man-made rulings superior to his contradicts the condition of faith the verse names.', 'fourth-nullifier', 'application');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-nw-06', 'quiz-nawaqid-al-islam', 'The fifth nullifier concerns a person who performs an act of the religion outwardly. What makes it a nullifier in his case?', '["That he performs the act without the correct method taught by the scholars","That he hates the very thing the Messenger ﷺ came with, even while acting upon it","That he performs it to be seen by people rather than for Allah","That he delays the act past its proper and legislated time"]'::jsonb, 1, 'The fifth nullifier is hatred of the revelation itself — ''that is because they hated what Allah revealed, so He rendered their deeds worthless'' (Muhammad 47:9). The outward action does not save him when the heart despises that Allah legislated it. Performing to be seen (option three) is riya, a different matter.', 'fifth-nullifier', 'application');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-nw-07', 'quiz-nawaqid-al-islam', 'Two friends joke that a bearded worshipper is ''overdoing the religion,'' laughing specifically at his adherence to the Sunnah. Which nullifier is the danger here, and what verse addresses it?', '["The eighth nullifier; al-Ma''idah 5:51 on allegiance to the mushrikun","The tenth nullifier; as-Sajdah 32:22 on turning away","The seventh nullifier; al-Baqarah 2:102 on magic","The sixth nullifier; at-Tawbah 9:65-66, revealed when some mocked the reciters at Tabuk"]'::jsonb, 3, 'Mocking something of the religion — Allah, the Quran, the Messenger ﷺ, or the reward and punishment — is the sixth nullifier. At-Tawbah 9:65-66 was revealed about men who mocked the Quran-reciters at Tabuk: ''Make no excuse; you have disbelieved after your belief.'' The other verses belong to different nullifiers.', 'sixth-nullifier', 'application');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-nw-08', 'quiz-nawaqid-al-islam', 'What did the two angels at Babylon say to everyone who came to learn magic, according to al-Baqarah 2:102?', '["That magic is permitted only for defending oneself from other magicians","That its knowledge should be passed only to trustworthy students","''We are only a trial, so do not disbelieve''","That it works solely by Allah''s decree and carries no sin"]'::jsonb, 2, 'The verse has the angels warn each learner: ''We are only a trial, so do not disbelieve.'' This frames magic (the seventh nullifier) as kufr in itself — the Quran ties learning and practicing it to disbelief, not to a permissible skill with conditions.', 'seventh-nullifier', 'recall');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-nw-09', 'quiz-nawaqid-al-islam', 'The ninth nullifier rejects the belief that some people may worship Allah outside the Shariah of Muhammad ﷺ. Which historical comparison does the text use to describe this false belief?', '["That such a person is like Khidr, who was permitted to act outside the law of Musa عليه السلام","That such a person is like the Companions before the laws were revealed in Madinah","That such a person is like the People of the Book following an earlier scripture","That such a person is like a traveler excused from certain obligations"]'::jsonb, 0, 'The ninth nullifier names exactly this claim: that someone may stand outside the Shariah of Muhammad ﷺ as al-Khidr stood outside the law of Musa. But the message of Muhammad ﷺ is for all people and times (Saba 34:28) — no saint or seeker is above it.', 'ninth-nullifier', 'recall');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-nw-10', 'quiz-nawaqid-al-islam', 'The author says there is no difference in these nullifiers between three types of people, with one exception. Which is the exception?', '["The one who is ignorant of the ruling until it reaches him","The one genuinely coerced, whose heart remains at rest upon faith","The one who repents immediately after committing the act","The one who is young and has not yet reached full maturity"]'::jsonb, 1, 'The author states there is no difference between the joker, the serious, and the fearful — except the one truly coerced whose heart is firm upon iman (the exception of an-Nahl 16:106). Ignorance and youth are treated elsewhere with their own conditions; the exception named here is coercion.', 'conditions', 'analysis');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-nw-11', 'quiz-nawaqid-al-islam', 'A student finishes this module and starts privately ranking his relatives by which nullifiers they might have fallen into. How does this misuse the chapter?', '["It doesn''t — identifying nullifiers in others is the direct purpose of the list","The list applies only to non-Muslims, so ranking Muslims by it is simply irrelevant","The chapter is for guarding one''s own Islam; ruling on specific individuals has conditions and barriers left to qualified scholars","He should rank them aloud with the community so corrective action can be taken"]'::jsonb, 2, 'The purpose is self-protection, not a tool for takfir of named people. Establishing that a specific person has committed a nullifier — with the conditions met and the barriers absent — is scholarly, judicial work. Turning the list into a private tribunal over relatives is precisely the error the framing warns against.', 'purpose', 'analysis');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-nw-12', 'quiz-nawaqid-al-islam', 'Which theme runs through most of the ten nullifiers, showing what the chapter is ultimately protecting?', '["The correct outward performance of the five daily prayers","The heart''s submission to Allah and His Messenger ﷺ — worship given only to Him, and no preference of another way over the revelation","The memorization of the Quran with proper tajweed","The maintenance of unity within the Muslim community"]'::jsonb, 1, 'Most nullifiers turn on the heart''s stance: directing worship elsewhere, preferring another guidance, hating or mocking the revelation, allegiance against the Muslims. The chapter guards the inner submission that the testimony expresses — which is why the author tells you to fear these for yourself.', 'conditions', 'analysis');
insert into public.quizzes (id, module_id) values ('quiz-usul-al-sittah', 'usul-al-sittah');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-us-01', 'quiz-usul-al-sittah', 'What recurring pattern does the author say runs through all six foundations?', '["Allah made a matter clear enough for the common person to grasp, yet most people opposed it","Each foundation was revealed in Madinah after the community was established","Every foundation depends on a hadith rather than a verse of the Quran","Each foundation was disputed only by the philosophers and theologians"]'::jsonb, 0, 'The author''s frame is that each of the six is so plain even an unlettered person would understand it — and yet the majority, including many who claimed knowledge, fell into its opposite. Seeing that pattern is the purpose of the whole treatise.', 'overview', 'recall');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-us-02', 'quiz-usul-al-sittah', 'The first foundation is sincerity (ikhlas) in the religion for Allah alone. What did most people do in opposition to it, per the author?', '["They abandoned the obligatory prayers while claiming inner faith","They directed acts of worship to intermediaries rather than to Allah alone","They denied that Allah is the Creator of the heavens and the earth","They invented new times and forms for the five daily prayers"]'::jsonb, 1, 'Ikhlas means worship purely for Allah, free of shirk. The opposition the author highlights is precisely giving worship to intermediaries — the same failure the categories of tawheed and the Four Principles diagnosed. Allah made the point plain (al-Bayyinah 98:5) yet most turned to others.', 'foundation-1', 'recall');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-us-03', 'quiz-usul-al-sittah', 'The second foundation commands unity in the religion and forbids division. According to the author, how did most people come to regard this?', '["They upheld unity so strictly that they forbade all scholarly differences","They came to treat division into sects as a mercy and unity upon truth as impossible","They limited unity to matters of prayer while dividing over creed","They believed unity was obligatory only under a single caliph"]'::jsonb, 1, 'Allah tied the ummah to one rope (Aal Imran 3:103) and forbade splitting (ash-Shura 42:13). The author observes the inversion: people came to regard sectarian division as a mercy and unity upon the truth as unattainable — the opposite of the command.', 'foundation-2', 'application');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-us-04', 'quiz-usul-al-sittah', 'A man argues: ''Since obeying the ruler is a foundation of religion, I must obey any command he gives, even one requiring sin.'' Where does his reasoning break, based on the third foundation?', '["Obedience to authority was abrogated and no longer applies after the first generation","The command to obey covers only religious scholars, never political authority","Obedience to a created being does not extend to disobedience of the Creator — it is in what is good","The foundation requires obedience only when the ruler is himself a scholar"]'::jsonb, 2, 'The third foundation joins obeying those in authority to obeying Allah and His Messenger (an-Nisa 4:59), but the Prophet ﷺ limited it: ''there is no obedience to a created being in disobedience to the Creator'' (al-Bukhari #7257). Obedience is in the good; a command to sin is not obeyed — while wholesale rejection of authority is also wrong.', 'foundation-3', 'application');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-us-05', 'quiz-usul-al-sittah', 'The fourth foundation clarifies who the true scholars are. Which verse does the author''s point rest on?', '["''Only those who have knowledge among His servants fear Allah'' (Fatir 35:28)","''And say: my Lord, increase me in knowledge'' (Ta-Ha 20:114)","''Read in the name of your Lord who created'' (al-''Alaq 96:1)","''Are those who know equal to those who do not know?'' (az-Zumar 39:9)"]'::jsonb, 0, 'The fourth foundation defines the scholar by fear of Allah born of knowing Him — ''only those with knowledge among His servants fear Allah'' (Fatir 35:28). The other verses praise knowledge generally but the author''s specific proof for who the true ulama are is Fatir 35:28.', 'foundation-4', 'recall');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-us-06', 'quiz-usul-al-sittah', 'According to the fifth foundation and Yunus 10:62-63, who are the true allies of Allah (awliya Allah)?', '["A hidden elite granted miraculous powers and knowledge of the unseen","The descendants of the Prophet ﷺ and the great scholars of each age","Those who believe and have taqwa — open to every believer, increasing with iman","Those who withdraw from society to devote themselves to constant worship"]'::jsonb, 2, 'Allah defined His awliya plainly: ''those who believed and were fearing Allah'' (Yunus 10:62-63). Wilayah is not a secret caste with strange powers; it grows with iman and taqwa and is open to any believer. The closer to Allah, the closer the following of His Messenger ﷺ — never the violation of the Shariah.', 'foundation-5', 'application');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-us-07', 'quiz-usul-al-sittah', 'The sixth foundation refutes a doubt the author calls one of Shaytan''s greatest tricks. What is that doubt?', '["That the Quran was altered like the earlier scriptures","That only a perfect, all-knowing mujtahid may derive from the Quran and Sunnah, so ordinary people should leave the texts entirely","That the Sunnah cannot be trusted because its chains are weak","That the religion was completed and needs no further study"]'::jsonb, 1, 'The sixth foundation answers the claim that the texts are sealed off from all but a flawless mujtahid, so the masses should abandon the Quran and Sunnah for blind imitation. The author calls it a device to empty people''s hands of revelation — refuted by Allah making the Book a clarification and guidance for all.', 'foundation-6', 'recall');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-us-08', 'quiz-usul-al-sittah', 'How does the sixth foundation answer that doubt about approaching the Quran and Sunnah?', '["By conceding the texts are only for scholars but urging the masses to memorize them anyway","By arguing that reason, not revelation, is the final authority in religion","By showing Allah made the Book a clarification and guidance for all people, easy to remember, meeting every doubt with truth","By restricting the Quran''s guidance to matters of worship and leaving all else to jurists"]'::jsonb, 2, 'The answer is that Allah made the Quran ''a clarification for all things, and guidance and mercy'' (an-Nahl 16:89), easy to remember (al-Qamar 54:17), and promised that no doubt comes except that He sends truth against it (al-Furqan 25:33). The Book is Allah''s accessible, standing proof — taken with the understanding of the people of knowledge, not abandoned.', 'foundation-6', 'application');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-us-09', 'quiz-usul-al-sittah', 'A speaker claims a certain man is a great wali of Allah because he reportedly flies and predicts the future, though he abandons the prayer. How does the fifth foundation assess this?', '["The claim stands, since miracles are the defining mark of Allah''s allies","It is rejected: wilayah is measured by iman and taqwa, and there is no nearness to Allah in abandoning His Shariah","It is accepted only if witnessed by several trustworthy people","It is a matter of opinion on which the texts are silent"]'::jsonb, 1, 'The fifth foundation ties wilayah to belief and taqwa, not to wonders. One who abandons the prayer cannot be a wali on the strength of alleged powers — the nearer a person is to Allah, the more he follows the Messenger ﷺ. Unusual feats without taqwa are no proof; they can even be from Shaytan''s imposters.', 'foundation-5', 'analysis');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-us-10', 'quiz-usul-al-sittah', 'The first and second foundations, taken together, explain a claim made elsewhere in this curriculum. Which?', '["That the prayer is the first pillar to be judged on the Day of Resurrection","That correct creed underlies communal unity — division in religion begins with corruption in aqeedah","That fasting was prescribed upon earlier nations before this one","That hajj combines bodily and financial worship"]'::jsonb, 1, 'Foundation one (sincere tawheed) and foundation two (unity, no division) connect directly: a community splinters when its creed corrupts, and it unites upon sound tawheed. This is why the whole library places aqeedah first — the foundations themselves make the link.', 'overview', 'analysis');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-us-11', 'quiz-usul-al-sittah', 'Why does the author repeatedly stress that these foundations are simple enough for a common person, yet opposed by many claimants to knowledge?', '["To argue that formal scholarship is unnecessary for understanding religion","To show that clarity of a truth is no guarantee people will accept it — so the student must hold to the evidence, not the crowd","To encourage students to bypass teachers and rely on their own reading","To prove that the common people are always more correct than the learned"]'::jsonb, 1, 'The contrast drives home that a matter can be crystal clear and still be widely rejected — so truth is measured by the evidence, not by numbers or reputations. It does not dismiss scholarship (the fourth foundation honors the true scholars); it warns against following the crowd against the proof.', 'overview', 'analysis');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-us-12', 'quiz-usul-al-sittah', 'Which ordering correctly matches each foundation to its theme?', '["1 sincerity, 2 unity, 3 obedience to authority, 4 the true scholars, 5 the allies of Allah, 6 answering the doubt about the texts","1 unity, 2 sincerity, 3 the scholars, 4 obedience, 5 the doubt about the texts, 6 the allies of Allah","1 obedience, 2 the allies of Allah, 3 sincerity, 4 unity, 5 the scholars, 6 the doubt about the texts","1 the scholars, 2 the allies of Allah, 3 the doubt about the texts, 4 sincerity, 5 unity, 6 obedience"]'::jsonb, 0, 'The six in order: sincerity for Allah alone; unity and the ban on division; hearing and obeying legitimate authority in good; clarifying the true scholars; clarifying the true allies of Allah; and refuting the doubt used to abandon the Quran and Sunnah. Holding the sequence helps you recall how the text builds.', 'overview', 'application');
insert into public.quizzes (id, module_id) values ('quiz-kashf-al-shubuhat', 'kashf-al-shubuhat');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-ks-01', 'quiz-kashf-al-shubuhat', 'What is the specific aim of Kashf al-Shubuhat, beyond simply teaching what tawheed is?', '["To list the rulings of worship in order of priority","To equip the student to recognize and dismantle the doubts raised against tawheed","To narrate the biography of the Prophet ﷺ and his call in Makkah","To enumerate the ninety-nine names of Allah with their meanings"]'::jsonb, 1, 'The treatise''s purpose is defensive: a person may know tawheed yet be shaken by a persuasively dressed doubt. Kashf al-Shubuhat — ''removal of the doubts'' — trains you to see exactly where each objection fails, so firmness comes from understanding, not just information.', 'purpose', 'recall');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-ks-02', 'quiz-kashf-al-shubuhat', 'The author begins by establishing that the mushrikun the Prophet ﷺ fought affirmed a certain kind of tawheed. Which, and why does it matter for answering doubts?', '["Tawheed al-uluhiyyah — which shows their worship was already correct","Tawheed al-asma wa''s-sifat — which shows they described Allah rightly","Tawheed ar-rububiyyah — showing their shirk lay in worship, not in denying the Creator","They affirmed no tawheed at all, being pure atheists"]'::jsonb, 2, 'They affirmed rububiyyah — that Allah alone creates and provides (Luqman 31:25). This is the master key: since their belief in the Creator was intact and still did not save them, the objection ''I can''t be like them, I believe in Allah'' collapses. The dispute was always over uluhiyyah — worship.', 'two-tawheeds', 'application');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-ks-03', 'quiz-kashf-al-shubuhat', 'Someone objects: ''The mushrikun of old bowed to stone idols. I turn to a righteous dead saint — that is completely different.'' How does the treatise remove this doubt?', '["By conceding the difference but noting the saint cannot hear either way","By showing the mushrikun themselves called upon righteous beings — angels, prophets, the pious — whom they considered close to Allah","By arguing that stone idols actually had more power than dead saints","By stating the ruling depends on the sincerity of the person''s heart"]'::jsonb, 1, 'The false picture is that the mushrikun only worshipped stones. In fact they called upon angels, prophets and righteous people as intermediaries — ''these are our intercessors with Allah.'' So directing worship to a righteous being is not a new, safer category; it is the very shirk the Quran condemned.', 'the-righteous', 'application');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-ks-04', 'quiz-kashf-al-shubuhat', 'The greatest doubt is: ''We don''t believe these beings create or provide; we only seek nearness and intercession through them.'' What is the author''s decisive answer?', '["This is a lesser error of etiquette, correctable by improving one''s intention","This is acceptable for the dead but not the living","This is word-for-word the excuse of the original mushrikun, which Allah reported in order to condemn — not to excuse","This is valid only if the intermediary was a prophet rather than a saint"]'::jsonb, 2, 'Az-Zumar 39:3 records this exact plea — ''we only worship them that they may bring us nearer to Allah'' — and Allah names it shirk, not a mitigating intention. The act of worship (du''a to another) is what counts; the noble stated purpose does not change the ruling.', 'nearness', 'application');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-ks-05', 'quiz-kashf-al-shubuhat', '''But intercession (shafa''ah) is real — you cannot deny it.'' How does the treatise affirm intercession yet still forbid calling on the dead for it?', '["Intercession is denied outright, so the request is baseless","Intercession belongs to Allah and is sought from Him; the believer asks Allah to grant it, not the deceased","Intercession may be requested from any righteous person, living or dead","Intercession is real only on the Day of Judgment, so requesting it now is pointless"]'::jsonb, 1, 'Intercession is real but wholly Allah''s — ''Say: to Allah belongs all intercession'' (az-Zumar 39:44) — and occurs only by His permission for those He is pleased with. So one says ''O Allah, grant me the intercession of Your Prophet ﷺ,'' turning to the Owner of intercession, rather than calling upon the dead directly. That is the line between tawheed and shirk.', 'intercession', 'application');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-ks-06', 'quiz-kashf-al-shubuhat', 'Surah al-Isra 17:57 says of some beings called upon besides Allah that they ''themselves seek the means of nearness to their Lord... hoping for His mercy and fearing His punishment.'' How does this verse answer the ''but they are righteous'' doubt?', '["It shows those righteous beings are themselves needy servants seeking Allah — so they cannot be objects of worship","It shows the righteous have the power to grant nearness to whoever calls them","It permits calling upon them since they are described as close to Allah","It refers only to the angels and excludes prophets and the pious"]'::jsonb, 0, 'The verse turns the doubt on its head: the very ones invoked are themselves seeking nearness to Allah, hoping for mercy and fearing punishment — needy servants, not deities. If they must seek Allah''s mercy, they cannot be a channel of worship directed away from Him. Righteousness makes them worshippers, not worshipped.', 'the-righteous', 'analysis');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-ks-07', 'quiz-kashf-al-shubuhat', 'What single principle does the treatise reduce every doubt to, once the objections are cleared away?', '["That sincerity of intention makes any act of devotion acceptable","That worship — with du''a at its core — is Allah''s right alone, and directing it elsewhere is shirk however it is dressed","That only prophets and angels may be sought as intermediaries","That belief in Allah as Creator is the essence of Islam"]'::jsonb, 1, 'Every doubt — nearness, intercession, the rank of the righteous — dissolves against one principle: worship belongs to Allah alone, and du''a is its core. However the objection is framed, directing worship to another is shirk. Holding this one line lets you hear any persuasive doubt and locate its flaw.', 'principle', 'recall');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-ks-08', 'quiz-kashf-al-shubuhat', 'A man says, ''When I call the saint, I know in my heart he is only a means, so it is not really worship.'' Using the treatise''s method, what is the flaw?', '["There is no flaw; inner intention determines whether an act is worship","The mushrikun said the same about their intermediaries, and Allah still named their act worship and shirk","The flaw is only that he should choose a more pious saint","The act is fine as long as he also prays the five daily prayers"]'::jsonb, 1, 'This is exactly the mushrikun''s own reasoning — ''we only worship them for nearness'' — which Allah quoted and condemned as shirk (az-Zumar 39:3, Yunus 10:18). Calling the act ''just a means'' does not remove it from being worship; the Quran already rejected that defense.', 'nearness', 'analysis');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-ks-09', 'quiz-kashf-al-shubuhat', 'Why does the author say the doubt ''but I call upon the righteous, not idols'' actually makes a person''s case worse, not better?', '["Because righteous people are more powerful than idols and so more effective to call","Because the earliest shirk arose precisely through veneration of righteous men, and the Quran named calling upon them shirk regardless of their rank","Because idols never existed and the comparison is therefore meaningless","Because the righteous would be angered and withhold their intercession"]'::jsonb, 1, 'The rank of the one called upon never converts the call into deserved worship — and history shows the first shirk (in the people of Nuh) grew from exaggerating dead righteous men. So invoking the pious is not a safer category; it is the original disease, and the Quran labels it shirk all the same.', 'the-righteous', 'analysis');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-ks-10', 'quiz-kashf-al-shubuhat', 'How does Kashf al-Shubuhat build on the Four Principles the student studied earlier?', '["It replaces them with a different definition of shirk","It takes the same diagnosis — rububiyyah affirmed, uluhiyyah denied, the nearness-and-intercession excuse — and trains the student to rebut it in live argument","It narrows the discussion to idols of stone only","It shifts the focus from shirk to the rulings of prayer and fasting"]'::jsonb, 1, 'The Four Principles laid out the diagnosis; Kashf al-Shubuhat weaponizes it for defense. Both rest on the mushrikun affirming the Creator while giving worship elsewhere, and both confront the ''nearness and intercession'' excuse — but Kashf trains you to answer the doubt when it is raised against you.', 'principle', 'analysis');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-ks-11', 'quiz-kashf-al-shubuhat', 'According to the treatise, what is the true difference between the muwahhid and the mushrik regarding intercession?', '["The muwahhid denies intercession entirely; the mushrik affirms it","The muwahhid seeks it from Allah, the Owner of intercession; the mushrik seeks it from the creature directly","The muwahhid seeks it from prophets; the mushrik seeks it from saints","There is no real difference; both hope for intercession"]'::jsonb, 1, 'Both affirm intercession is real. The dividing line is the direction of the request: the believer asks Allah — ''to Allah belongs all intercession'' (az-Zumar 39:44) — while the mushrik directs his call to the creature. Same hoped-for outcome; opposite acts, and opposite creeds.', 'intercession', 'recall');
insert into public.quiz_questions (id, quiz_id, question_text, options, correct_answer_index, explanation, topic_tag, difficulty) values ('q-ks-12', 'quiz-kashf-al-shubuhat', 'What does the treatise identify as the real dividing line between tawheed and shirk — the point every doubt tries to blur?', '["Whether a person affirms that Allah exists and created the world","Whether a person performs the five pillars outwardly","To whom worship — especially du''a — is directed, not whether one believes in a Creator","Whether a person belongs to a Muslim family and community"]'::jsonb, 2, 'Every doubt tries to relocate the line to ''belief in God,'' which the mushrikun already had. The treatise keeps the line where the Quran puts it: the direction of worship. Believe in the Creator and still call on others in worship, and you have crossed from tawheed into shirk.', 'principle', 'analysis');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-adhan', 'أَذَان', 'Adhan', 'The call to prayer announced before each of the five daily prayers.', 'Fiqh');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-ahad', 'آحَاد', 'Ahad', 'A hadith narrated through a limited number of chains, below the level of mutawatir.', 'Hadith');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-ahlus-sunnah', 'أَهْلُ السُّنَّةِ وَالْجَمَاعَة', 'Ahlus Sunnah wal-Jama''ah', 'The people who hold to the Sunnah of the Prophet ﷺ and the way of his Companions, avoiding innovation and division.', 'Aqeedah');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-alhamdulillah', 'الْحَمْدُ لِلَّه', 'Alhamdulillah', '"All praise is due to Allah" — the expression of gratitude and praise to Allah.', 'General');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-amanah', 'أَمَانَة', 'Amanah', 'A trust or responsibility that must be discharged faithfully.', 'General');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-aqeedah', 'عَقِيدَة', 'Aqeedah', 'Creed; the matters of belief a Muslim ties his heart to — concerning Allah, His angels, books, messengers, the Last Day and the decree.', 'Aqeedah');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-arkan', 'أَرْكَان', 'Arkan', 'Pillars; the essential components of an act of worship without which it is invalid.', 'Fiqh');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-asma-sifat', 'الأَسْمَاءُ وَالصِّفَات', 'Asma wa''s-Sifat', 'Allah''s names and attributes, affirmed as revealed — without distortion, denial, asking how, or likening to creation.', 'Aqeedah');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-athar', 'أَثَر', 'Athar', 'A report transmitted from a Companion or one of the Salaf, as distinct from a hadith of the Prophet ﷺ.', 'Hadith');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-ayah', 'آيَة', 'Ayah', 'A verse of the Quran; literally a "sign" pointing to Allah.', 'Quran');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-barakah', 'بَرَكَة', 'Barakah', 'Blessing; divinely placed increase and goodness in something.', 'General');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-basmalah', 'بَسْمَلَة', 'Basmalah', 'The phrase "Bismillah ir-Rahman ir-Raheem" — in the name of Allah, the Most Merciful, the Bestower of mercy.', 'Quran');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-bidah', 'بِدْعَة', 'Bid''ah', 'Innovation in religion: a newly invented act of worship with no basis in the Quran or Sunnah. Every bid''ah in worship is misguidance.', 'Aqeedah');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-daeef', 'ضَعِيف', 'Da''eef', 'A weak hadith: one failing the conditions of authenticity in its chain or text.', 'Hadith');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-dawah', 'دَعْوَة', 'Da''wah', 'Inviting people to Allah — to tawheed and obedience — with knowledge, wisdom and good admonition.', 'Dawah');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-deen', 'دِين', 'Deen', 'Religion; the complete way of life Allah legislated — belief, worship, dealings and character.', 'General');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-dhikr', 'ذِكْر', 'Dhikr', 'Remembrance of Allah with the tongue and heart, using legislated words of praise and glorification.', 'General');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-dua', 'دُعَاء', 'Du''a', 'Supplication; asking Allah directly. The Prophet ﷺ said du''a is worship — so it may be directed to none but Allah.', 'Aqeedah');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-fajr', 'فَجْر', 'Fajr', 'The dawn; the first obligatory prayer of the day, prayed before sunrise.', 'Fiqh');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-fatwa', 'فَتْوَى', 'Fatwa', 'A religious verdict issued by a qualified scholar in answer to a question.', 'Fiqh');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-fiqh', 'فِقْه', 'Fiqh', 'Understanding of the practical rulings of the Shariah — worship, transactions, family law — derived from the evidences.', 'Fiqh');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-fitnah', 'فِتْنَة', 'Fitnah', 'Trial, tribulation or temptation that tests faith; also used for discord among people.', 'General');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-fitrah', 'فِطْرَة', 'Fitrah', 'The innate natural disposition upon which Allah created mankind — inclining to tawheed before external influences corrupt it.', 'Aqeedah');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-ghayb', 'غَيْب', 'Ghayb', 'The unseen: everything beyond human perception that is known only through revelation — the angels, the grave, the Last Day.', 'Aqeedah');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-ghusl', 'غُسْل', 'Ghusl', 'The full ritual bath required to remove major impurity.', 'Fiqh');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-hadith', 'حَدِيث', 'Hadith', 'A transmitted report of the Prophet''s ﷺ statements, actions, approvals or descriptions.', 'Hadith');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-hafiz', 'حَافِظ', 'Hafiz', 'One who has memorized the entire Quran; in hadith science, a master memorizer of narrations.', 'Quran');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-hajj', 'حَجّ', 'Hajj', 'The pilgrimage to the Sacred House in Makkah — the fifth pillar of Islam, obligatory once upon the able.', 'Fiqh');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-halal', 'حَلَال', 'Halal', 'That which Allah has made lawful.', 'Fiqh');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-hanif', 'حَنِيف', 'Hanif', 'One who inclines away from shirk to pure tawheed — the description of Ibrahim عليه السلام.', 'Aqeedah');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-haram', 'حَرَام', 'Haram', 'That which Allah has forbidden; committing it is sin and leaving it is worship.', 'Fiqh');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-hasan', 'حَسَن', 'Hasan', 'A "good" hadith: authentic and acceptable as proof, though below sahih in precision of narrators.', 'Hadith');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-hijrah', 'هِجْرَة', 'Hijrah', 'Migration for the sake of Allah — historically, the Prophet''s ﷺ move from Makkah to Madinah.', 'General');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-hukm', 'حُكْم', 'Hukm', 'A ruling of the Shariah concerning an action: obligatory, recommended, permissible, disliked, or forbidden.', 'Fiqh');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-ibadah', 'عِبَادَة', 'Ibadah', 'Worship: a comprehensive term for everything Allah loves and is pleased with, of statements and actions, inward and outward.', 'Aqeedah');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-ihsan', 'إِحْسَان', 'Ihsan', 'The highest level of the religion: to worship Allah as though you see Him — and though you do not see Him, He sees you.', 'Aqeedah');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-ijma', 'إِجْمَاع', 'Ijma''', 'The consensus of the qualified scholars of the ummah on a ruling — a binding proof in Islam.', 'Fiqh');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-ikhlas', 'إِخْلَاص', 'Ikhlas', 'Sincerity: purifying one''s worship so that it is done for Allah alone, seeking neither praise nor position.', 'Aqeedah');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-ilm', 'عِلْم', 'Ilm', 'Knowledge — in the Shariah''s usage: knowledge of Allah, His religion and His Messenger ﷺ, built on evidence.', 'General');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-imam', 'إِمَام', 'Imam', 'A leader — of the prayer, or a scholar of great standing followed in knowledge.', 'General');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-iman', 'إِيمَان', 'Iman', 'Faith: statement of the tongue, belief of the heart and action of the limbs; it increases with obedience and decreases with sin.', 'Aqeedah');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-iqamah', 'إِقَامَة', 'Iqamah', 'The second call announcing that the congregational prayer is beginning.', 'Fiqh');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-isnad', 'إِسْنَاد', 'Isnad', 'The chain of narrators through which a hadith is transmitted — the science that preserved the Sunnah.', 'Hadith');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-istighfar', 'اِسْتِغْفَار', 'Istighfar', 'Seeking Allah''s forgiveness, especially with the words "astaghfirullah".', 'General');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-istiwa', 'اِسْتِوَاء', 'Istiwa', 'Allah''s rising over the Throne, affirmed as He revealed it: the rising is known, the how is unknown, and asking about the how is an innovation.', 'Aqeedah');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-itikaf', 'اِعْتِكَاف', 'I''tikaf', 'Devotional seclusion in the mosque, especially in the last ten nights of Ramadan.', 'Fiqh');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-jahiliyyah', 'جَاهِلِيَّة', 'Jahiliyyah', 'The pre-Islamic age of ignorance; also any practice that belongs to it.', 'General');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-jibreel', 'جِبْرِيل', 'Jibreel', 'The angel entrusted with bringing revelation to the prophets — the greatest of the angels.', 'Aqeedah');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-jinn', 'جِنّ', 'Jinn', 'A created world of beings made from smokeless fire, unseen by us, accountable like mankind for worshipping Allah.', 'Aqeedah');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-jumuah', 'جُمُعَة', 'Jumu''ah', 'Friday; the weekly congregational prayer and sermon that replaces Dhuhr for men.', 'Fiqh');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-kabah', 'كَعْبَة', 'Ka''bah', 'The Sacred House in Makkah built by Ibrahim and Isma''il, the direction of prayer for all Muslims.', 'General');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-kufr', 'كُفْر', 'Kufr', 'Disbelief: rejection of Allah or of what His Messenger ﷺ came with, whether by denial, arrogance or aversion.', 'Aqeedah');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-la-ilaha', 'لَا إِلَٰهَ إِلَّا اللَّه', 'La ilaha illa Allah', 'The word of tawheed: none has the right to be worshipped except Allah — negating worship of all else, affirming it for Him alone.', 'Aqeedah');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-madhhab', 'مَذْهَب', 'Madhhab', 'A school of jurisprudence — Hanafi, Maliki, Shafi''i or Hanbali — each a scholarly methodology for deriving rulings.', 'Fiqh');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-makruh', 'مَكْرُوه', 'Makruh', 'Disliked: an act better left; leaving it is rewarded and doing it is not sinful.', 'Fiqh');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-manhaj', 'مَنْهَج', 'Manhaj', 'Methodology: the path one takes in creed, learning, practice and da''wah — soundest when it follows the Salaf.', 'Aqeedah');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-masjid', 'مَسْجِد', 'Masjid', 'A mosque; literally, a place of prostration.', 'General');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-matn', 'مَتْن', 'Matn', 'The text of a hadith (as opposed to its chain); also a concise classical text composed for study, like Thalathat al-Usul.', 'Hadith');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-mubah', 'مُبَاح', 'Mubah', 'Permissible: an act carrying neither reward nor sin in itself.', 'Fiqh');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-mufti', 'مُفْتِي', 'Mufti', 'A scholar qualified to issue fatawa.', 'Fiqh');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-muhaddith', 'مُحَدِّث', 'Muhaddith', 'A scholar of hadith — its chains, narrators, texts and grading.', 'Hadith');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-mushrik', 'مُشْرِك', 'Mushrik', 'One who commits shirk, directing worship to others besides Allah.', 'Aqeedah');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-mustahabb', 'مُسْتَحَبّ', 'Mustahabb', 'Recommended: rewarded if done, not sinful if left.', 'Fiqh');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-mutawatir', 'مُتَوَاتِر', 'Mutawatir', 'A hadith transmitted by so many narrators at every level that fabrication is impossible.', 'Hadith');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-nabi', 'نَبِيّ', 'Nabi', 'A prophet: a man given revelation from Allah. Every messenger is a prophet, but not every prophet a messenger.', 'Aqeedah');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-nahw', 'نَحْو', 'Nahw', 'Arabic grammar — the science of sentence structure and case endings, classically begun with al-Ajurrumiyyah.', 'Arabic');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-nifaq', 'نِفَاق', 'Nifaq', 'Hypocrisy: displaying Islam while concealing disbelief (major), or having traits like lying and betraying trusts (minor).', 'Aqeedah');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-niyyah', 'نِيَّة', 'Niyyah', 'Intention: the heart''s resolve that distinguishes worship from habit — "actions are only by intentions".', 'Fiqh');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-nisab', 'نِصَاب', 'Nisab', 'The minimum threshold of wealth upon which zakah becomes due.', 'Fiqh');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-qadar', 'قَدَر', 'Qadar', 'The divine decree: Allah''s knowledge, writing, will and creation of all things — the sixth pillar of iman.', 'Aqeedah');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-qiblah', 'قِبْلَة', 'Qiblah', 'The direction of prayer, toward the Ka''bah in Makkah.', 'Fiqh');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-qiyam', 'قِيَامُ اللَّيْل', 'Qiyam al-Layl', 'Voluntary prayer in the night, the most virtuous prayer after the obligatory ones.', 'Fiqh');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-quran', 'قُرْآن', 'Quran', 'The speech of Allah revealed to Muhammad ﷺ — recited in worship, preserved unaltered, the final revelation.', 'Quran');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-rakah', 'رَكْعَة', 'Rak''ah', 'One complete unit of prayer: standing, bowing, and two prostrations.', 'Fiqh');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-ramadan', 'رَمَضَان', 'Ramadan', 'The ninth month of the Islamic calendar, in which fasting is obligatory and the Quran was sent down.', 'Fiqh');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-rasul', 'رَسُول', 'Rasul', 'A messenger: a prophet sent with a message to convey to a people.', 'Aqeedah');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-riba', 'رِبَا', 'Riba', 'Usury/interest — increase stipulated in loans or unequal exchange of like currencies; among the gravest of sins.', 'Fiqh');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-riya', 'رِيَاء', 'Riya', 'Performing worship to be seen and praised by people — the "hidden shirk" the Prophet ﷺ feared for his ummah.', 'Aqeedah');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-rububiyyah', 'رُبُوبِيَّة', 'Rububiyyah', 'Allah''s Lordship: His oneness in creating, owning, providing and governing all things.', 'Aqeedah');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-ruqyah', 'رُقْيَة', 'Ruqyah', 'Legislated healing through recitation of the Quran and authentic supplications.', 'Fiqh');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-sabr', 'صَبْر', 'Sabr', 'Patience: restraining the soul upon obedience, away from sin, and under the decree.', 'General');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-sadaqah', 'صَدَقَة', 'Sadaqah', 'Voluntary charity, given at any time and in any amount.', 'Fiqh');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-sahabah', 'صَحَابَة', 'Sahabah', 'The Companions: those who met the Prophet ﷺ believing in him and died upon Islam — the best generation.', 'General');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-sahih', 'صَحِيح', 'Sahih', 'Authentic: a hadith whose chain is connected through upright, precise narrators, free of defects.', 'Hadith');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-salaf', 'سَلَف', 'Salaf', 'The righteous predecessors: the first three praised generations — the Companions, the Tabi''un, and their followers.', 'Aqeedah');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-salah', 'صَلَاة', 'Salah', 'The prescribed prayer — the second pillar of Islam, performed five times daily.', 'Fiqh');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-sarf', 'صَرْف', 'Sarf', 'Arabic morphology: the science of word patterns and derivation.', 'Arabic');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-sawm', 'صَوْم', 'Sawm', 'Fasting: abstaining from food, drink and marital relations from true dawn to sunset as worship.', 'Fiqh');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-seerah', 'سِيرَة', 'Seerah', 'The biography of the Prophet ﷺ.', 'General');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-shahadah', 'شَهَادَة', 'Shahadah', 'The testimony of faith: none has the right to be worshipped except Allah, and Muhammad is His Messenger.', 'Aqeedah');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-shariah', 'شَرِيعَة', 'Shari''ah', 'The revealed law of Islam in its entirety — creed, worship, dealings and ethics.', 'Fiqh');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-shaytan', 'شَيْطَان', 'Shaytan', 'Satan — Iblis and his followers among jinn and men who call away from Allah.', 'Aqeedah');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-shirk', 'شِرْك', 'Shirk', 'Associating partners with Allah in His lordship, worship, or names and attributes — the one sin not forgiven if died upon unrepentant.', 'Aqeedah');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-shubhah', 'شُبْهَة', 'Shubhah', 'A doubt or specious argument that beautifies falsehood; treated by returning to clear texts and firm scholars.', 'Aqeedah');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-sunnah', 'سُنَّة', 'Sunnah', 'The Prophet''s ﷺ way: his statements, actions and approvals — the second revelation alongside the Quran.', 'Hadith');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-surah', 'سُورَة', 'Surah', 'A chapter of the Quran; there are 114.', 'Quran');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-tabiun', 'تَابِعُون', 'Tabi''un', 'The generation who learned from the Companions — the second of the praised generations.', 'General');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-tafsir', 'تَفْسِير', 'Tafsir', 'Explanation of the Quran — soundest when the Quran is explained by the Quran, the Sunnah, and the understanding of the Salaf.', 'Quran');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-taghut', 'طَاغُوت', 'Taghut', 'Everything worshipped, followed or obeyed besides Allah while it is pleased with that — disbelief in it is half of the shahadah.', 'Aqeedah');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-taharah', 'طَهَارَة', 'Taharah', 'Purification from ritual impurity and filth — the key to the prayer.', 'Fiqh');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-tahrif', 'تَحْرِيف', 'Tahrif', 'Distorting the wording or meaning of Allah''s names and attributes — one of the four errors the Salafi creed avoids.', 'Aqeedah');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-tajweed', 'تَجْوِيد', 'Tajweed', 'The science of reciting the Quran correctly, giving every letter its right.', 'Quran');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-takbir', 'تَكْبِير', 'Takbir', 'Saying "Allahu Akbar" — Allah is greater than everything.', 'Fiqh');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-takyif', 'تَكْيِيف', 'Takyif', 'Asking or asserting *how* Allah''s attributes are — negated, since the how is known only to Him.', 'Aqeedah');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-talbiyah', 'تَلْبِيَة', 'Talbiyah', 'The pilgrim''s proclamation: "Labbayk Allahumma labbayk..." — Here I am, O Allah, here I am; You have no partner.', 'Fiqh');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-tamthil', 'تَمْثِيل', 'Tamthil', 'Likening Allah''s attributes to those of creation — negated by "there is nothing like Him" (42:11).', 'Aqeedah');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-taqwa', 'تَقْوَى', 'Taqwa', 'Mindful fear of Allah: placing a shield between yourself and His anger by doing what He commands and leaving what He forbids.', 'General');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-tashahhud', 'تَشَهُّد', 'Tashahhud', 'The sitting testimony recited in prayer, containing the greeting and the shahadatayn.', 'Fiqh');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-tatil', 'تَعْطِيل', 'Ta''til', 'Denying or stripping away Allah''s names and attributes — the error of the extreme negators.', 'Aqeedah');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-tawaf', 'طَوَاف', 'Tawaf', 'Circumambulating the Ka''bah seven times in worship.', 'Fiqh');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-tawakkul', 'تَوَكُّل', 'Tawakkul', 'Reliance upon Allah: entrusting outcomes to Him while taking the means He legislated.', 'Aqeedah');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-tawbah', 'تَوْبَة', 'Tawbah', 'Repentance: leaving the sin, regretting it, resolving not to return — and restoring rights if others were wronged.', 'General');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-tawheed', 'تَوْحِيد', 'Tawheed', 'Singling out Allah alone — in His lordship, His worship, and His names and attributes. The core of Islam and the message of every prophet.', 'Aqeedah');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-tayammum', 'تَيَمُّم', 'Tayammum', 'Dry purification with clean earth when water is unavailable or harmful.', 'Fiqh');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-ulama', 'عُلَمَاء', 'Ulama', 'The scholars — the inheritors of the prophets, who carry knowledge with evidence.', 'General');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-uluhiyyah', 'أُلُوهِيَّة', 'Uluhiyyah', 'Allah''s sole right to worship: the tawheed contained in "la ilaha illa Allah" and the point over which the messengers were sent.', 'Aqeedah');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-ummah', 'أُمَّة', 'Ummah', 'The global community of Muslims; also, a nation to whom a messenger was sent.', 'General');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-umrah', 'عُمْرَة', 'Umrah', 'The lesser pilgrimage: ihram, tawaf and sa''i, performable at any time of year.', 'Fiqh');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-usul', 'أُصُول', 'Usul', 'Foundations or principles — as in usul al-din (foundations of the religion) and usul al-fiqh (principles of jurisprudence).', 'General');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-wahy', 'وَحْي', 'Wahy', 'Revelation: Allah''s communication to His prophets, whether Quran or Sunnah.', 'Quran');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-wajib', 'وَاجِب', 'Wajib', 'Obligatory: rewarded if done, sinful if abandoned.', 'Fiqh');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-wudu', 'وُضُوء', 'Wudu', 'Ablution: the washing legislated before prayer — a condition for its validity.', 'Fiqh');
insert into public.glossary_terms (id, arabic_term, transliteration, definition, category) values ('g-zakah', 'زَكَاة', 'Zakah', 'The obligatory annual due on qualifying wealth — the third pillar of Islam, purifying giver and property.', 'Fiqh');
